import ApiClient from './index';
import type { MediaResource, PlaySource } from '@/types/media';
import type { User } from '@/types/user';

export interface AdminPaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export interface AdminSystemStats {
  userCount: number;
  mediaCount: number;
  playSourceCount: number;
  watchHistoryCount: number;
  downloadTaskCount: number;
  activeDownloadTaskCount: number;
  completedDownloadTaskCount: number;
  failedDownloadTaskCount: number;
  recentActivity: Array<Record<string, unknown>>;
}

export interface AdminHealthStatus {
  status: string;
  timestamp: string;
  uptime: number;
  memory: {
    rss: number;
    heapUsed: number;
    heapTotal: number;
  };
}

export interface AdminDanmakuHealthStatus {
  status: 'healthy';
  database: 'connected';
  websocket: 'active';
  performance: {
    responseTime: 'normal';
    memoryUsage: 'normal';
    activeConnections: number;
    activeRooms: number;
    totalMessages: number;
  };
  lastUpdate: string;
  uptime: number;
  message: string;
}

export interface AdminLogItem {
  id: number;
  action: string;
  resource: string;
  status: 'success' | 'error' | 'warning';
  metadata?: Record<string, unknown>;
  description?: string;
  errorMessage?: string;
  requestInfo?: {
    ip?: string;
    userAgent?: string;
    method?: string;
    url?: string;
  };
  roleId: number;
  userId?: number;
  createdAt: string;
  role?: { name?: string };
  user?: Pick<User, 'id' | 'username' | 'email'>;
}

export interface AdminRoleItem {
  id: number;
  name: string;
  description?: string;
  permissions?: string[];
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface AdminRolePayload {
  name: string;
  description?: string;
  permissions?: string[];
  isActive?: boolean;
}

export interface AdminPermissionItem {
  id: number;
  code: string;
  name: string;
  description?: string;
  resource?: string;
  action?: string;
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface AdminPermissionPayload {
  code: string;
  name: string;
  description?: string;
  resource?: string;
  action?: string;
  isActive?: boolean;
}

export interface AdminWatchHistoryItem {
  id: number;
  currentTime: number;
  duration?: number;
  watchDuration: number;
  isCompleted: boolean;
  playCount: number;
  updatedAt: string;
  createdAt: string;
  userId: number;
  mediaResourceId: number;
  user?: Pick<User, 'id' | 'username' | 'email' | 'avatar'>;
  mediaResource?: Pick<MediaResource, 'id' | 'title' | 'type' | 'poster'>;
  progress?: {
    currentTime: number;
    duration: number;
    percentage: number;
  };
}

export interface AdminDownloadTaskItem {
  id: number;
  clientId: string;
  url: string;
  type: 'direct' | 'torrent' | 'magnet';
  status: 'pending' | 'downloading' | 'paused' | 'completed' | 'error' | 'cancelled';
  progress: number;
  speed: number;
  downloaded: number;
  total: number;
  fileName: string;
  filePath?: string;
  sourceLabel?: string;
  handler?: 'browser' | 'system';
  launchCount?: number;
  error?: string;
  metadata?: Record<string, unknown>;
  userId: number;
  mediaResourceId?: number | null;
  createdAt: string;
  updatedAt: string;
  completedAt?: string | null;
  lastLaunchedAt?: string | null;
  user?: Pick<User, 'id' | 'username' | 'email' | 'nickname'>;
  mediaResource?: Pick<MediaResource, 'id' | 'title' | 'type' | 'poster'>;
}

export interface AdminDownloadTaskActionPayload {
  action: 'retry' | 'cancel';
}

export interface AdminBatchDownloadTaskActionPayload extends AdminDownloadTaskActionPayload {
  ids: number[];
}

export const adminApi = {
  getStats: () => ApiClient.get<AdminSystemStats>('/admin/stats', undefined, false),

  getHealth: () => ApiClient.get<AdminHealthStatus>('/admin/health', undefined, false),

  getDanmakuHealth: () =>
    ApiClient.get<AdminDanmakuHealthStatus>('/danmaku/health', undefined, false),

  getUsers: (params?: { page?: number; limit?: number; search?: string }) =>
    ApiClient.get<AdminPaginatedResponse<User>>('/admin/users', { params }, false),

  getMedia: (params?: { page?: number; limit?: number; type?: string; search?: string }) =>
    ApiClient.get<AdminPaginatedResponse<MediaResource>>('/admin/media', { params }, false),

  getRoles: () => ApiClient.get<AdminRoleItem[]>('/admin/roles', undefined, false),

  createRole: (payload: AdminRolePayload) => ApiClient.post<AdminRoleItem>('/admin/roles', payload),

  updateRole: (id: number, payload: Partial<AdminRolePayload>) =>
    ApiClient.patch<AdminRoleItem>(`/admin/roles/${id}`, payload),

  getPermissions: () =>
    ApiClient.get<AdminPermissionItem[]>('/admin/permissions', undefined, false),

  createPermission: (payload: AdminPermissionPayload) =>
    ApiClient.post<AdminPermissionItem>('/admin/permissions', payload),

  updatePermission: (id: number, payload: Partial<AdminPermissionPayload>) =>
    ApiClient.patch<AdminPermissionItem>(`/admin/permissions/${id}`, payload),

  getPlaySources: (params?: {
    page?: number;
    limit?: number;
    type?: string;
    source?: string;
    sources?: string;
    search?: string;
    status?: string;
    sortBy?: 'createdAt' | 'lastCheckedAt' | 'priority';
    sortOrder?: 'ASC' | 'DESC';
  }) => ApiClient.get<AdminPaginatedResponse<PlaySource>>('/admin/play-sources', { params }, false),

  getWatchHistory: (params?: { page?: number; limit?: number; userId?: number }) =>
    ApiClient.get<AdminPaginatedResponse<AdminWatchHistoryItem>>(
      '/admin/watch-history',
      { params },
      false,
    ),

  getDownloadTasks: (params?: {
    page?: number;
    limit?: number;
    status?: AdminDownloadTaskItem['status'];
    type?: AdminDownloadTaskItem['type'];
    userId?: number;
    mediaResourceId?: number;
    search?: string;
    clientId?: string;
    hash?: string;
    taskId?: number;
  }) =>
    ApiClient.get<AdminPaginatedResponse<AdminDownloadTaskItem>>(
      '/admin/download-tasks',
      { params },
      false,
    ),

  handleDownloadTask: (id: number, payload: AdminDownloadTaskActionPayload) =>
    ApiClient.patch<AdminDownloadTaskItem>(`/admin/download-tasks/${id}`, payload),

  handleDownloadTasksBatch: (payload: AdminBatchDownloadTaskActionPayload) =>
    ApiClient.patch<AdminDownloadTaskItem[]>('/admin/download-tasks/batch', payload),

  getLogs: (params?: {
    page?: number;
    limit?: number;
    action?: string;
    resource?: string;
    status?: 'success' | 'error' | 'warning';
    roleId?: number;
    clientId?: string;
    hash?: string;
    downloadTaskId?: number;
    logId?: number;
  }) => ApiClient.get<AdminPaginatedResponse<AdminLogItem>>('/admin/logs', { params }, false),
};

import ApiClient from './index';
import type { 
  LoginCredentials, 
  RegisterUserData, 
  AuthResponse, 
  User 
} from '@/types/user';

export const authApi = {
  // 用户登录
  login: (credentials: LoginCredentials) => {
    return ApiClient.post<AuthResponse>('/users/login', credentials);
  },

  // 用户注册
  register: (userData: RegisterUserData) => {
    return ApiClient.post<User>('/users/register', userData);
  },

  // 获取用户信息
  getProfile: () => {
    return ApiClient.get<User>('/users/profile', undefined, false); // 不使用缓存
  },

  // 更新用户信息
  updateProfile: (userData: Partial<User>) => {
    return ApiClient.put<User>('/users/profile', userData);
  },

  // 修改密码
  changePassword: (passwordData: { oldPassword: string; newPassword: string }) => {
    return ApiClient.put<{ success: true }>('/users/change-password', passwordData);
  },

  // 检查令牌有效性
  validateToken: async () => {
    try {
      const user = await ApiClient.get<User>('/users/profile', undefined, false);
      return {
        valid: true,
        user,
      };
    } catch {
      return {
        valid: false,
        user: null,
      };
    }
  },

  // 退出登录由前端本地清理令牌完成；当前后端没有单独的 /auth/logout 端点
  logout: async () => undefined,
};

import ApiClient from './index';

export interface CrawlerTarget {
  name: string;
  baseUrl: string;
  enabled?: boolean;
  status?: 'online' | 'offline' | 'unknown';
}

export interface CrawlPersistence {
  mediaResourceId: number;
  created: boolean;
  playSourceCount: number;
  skippedPlaySources: number;
}

export interface CrawlResultData {
  title: string;
  description?: string;
  type: string;
  rating: number;
  source: string;
  director?: string;
  actors?: string;
  genres?: string[];
  releaseDate?: string;
  episodeCount?: number;
  duration?: number;
  poster?: string;
  backdrop?: string;
  downloadUrls?: string[];
  metadata?: Record<string, unknown>;
}

export interface CrawlResultResponse {
  success: boolean;
  message: string;
  data?: CrawlResultData;
  persistence?: CrawlPersistence | null;
  error?: string;
}

export interface BatchCrawlResponse {
  success: boolean;
  message: string;
  data?: {
    crawledData: CrawlResultData[];
    successCount: number;
    failureCount: number;
    savedCount: number;
    totalRequested: number;
  };
}

export interface CollectedSourceSummary {
