  attempted: number;
  succeeded: number;
  failed: number;
  skippedNoPlayableUrls: number;
  createdMedia: number;
  createdPlaySources: number;
  skippedPlaySources: number;
  urls: string[];
  errors: string[];
}

export interface CollectPopularResponse {
  success: boolean;
  message: string;
  data?: CollectedSourceSummary;
}

export interface SourceHealthSummary {
  name: string;
  baseUrl: string;
  dailyEnabled: boolean;
  dailyLimit: number;
  proxyMode: 'direct' | 'prefer-proxy' | 'proxy-required';
  proxyForDiscovery: boolean;
  proxyForDetail: boolean;
  proxyForConnectivityCheck: boolean;
  requirePlayableUrls: boolean;
  minimumPlayableUrls: number;
  suggestedProxyMode: 'direct' | 'prefer-proxy' | 'proxy-required';
  qualityScore: number;
  extractionCoverage: number;
  recentMedia7d: number;
  qualityBreakdown: {
    availability: number;
    freshness: number;
    extraction: number;
    inventory: number;
    validation: number;
  };
  recommendation: string;
  totalPlaySources: number;
  activePlaySources: number;
  inactivePlaySources: number;
  recentPlaySources24h: number;
  activeRate: number;
  latestCreatedAt: string | null;
  latestCheckedAt: string | null;
}

export interface SourcePolicyUpdatePayload {
  dailyEnabled?: boolean;
  dailyLimit?: number;
  proxyMode?: 'direct' | 'prefer-proxy' | 'proxy-required';
  proxyForDiscovery?: boolean;
  proxyForDetail?: boolean;
  proxyForConnectivityCheck?: boolean;
  requirePlayableUrls?: boolean;
  minimumPlayableUrls?: number;
}

export interface CollectionSourceStatistics {
  name: string;
  enabled: boolean;
  dailyEnabled: boolean;
  totalCrawled: number;
  activeMedia: number;
  totalPlaySources: number;
  activePlaySources: number;
  recentPlaySources24h: number;
  activeRate: number;
  qualityScore: number;
  extractionCoverage: number;
  recentMedia7d: number;
  qualityBreakdown: {
    availability: number;
    freshness: number;
    extraction: number;
    inventory: number;
    validation: number;
  };
  proxyMode: 'direct' | 'prefer-proxy' | 'proxy-required';
  proxyForDiscovery: boolean;
  proxyForDetail: boolean;
  proxyForConnectivityCheck: boolean;
  suggestedProxyMode: 'direct' | 'prefer-proxy' | 'proxy-required';
  lastCrawled: string | null;
  lastPlaySourceCreatedAt: string | null;
  lastCheckedAt: string | null;
}

export interface CollectionStatistics {
  totalSources: number;
  enabledSources: number;
  dailyEnabledSources: number;
  stableSources: number;
  totalMedia: number;
  activeMedia: number;
  totalPlaySources: number;
  activePlaySources: number;
  recentPlaySources24h: number;
  averageActiveRate: number;
  averageQualityScore: number;
  latestCollectedAt: string | null;
  latestValidatedAt: string | null;
  sources: CollectionSourceStatistics[];
}

export interface StatisticsResponse {
  success: boolean;
  message: string;
  data?: CollectionStatistics;
}

export const crawlerApi = {
  getTargets: async (): Promise<CrawlerTarget[]> => {
    const response = await ApiClient.get<{ success: boolean; data: CrawlerTarget[] }>(
      '/crawler/targets',
    );
    return response.data || [];
  },

  testConnection: (targetName: string) =>
    ApiClient.get<{ success: boolean }>(
      `/crawler/test-connection?targetName=${encodeURIComponent(targetName)}`,
    ),

  crawl: (payload: { url: string; targetName: string }) =>
    ApiClient.post<CrawlResultResponse>('/crawler/crawl', payload),

  crawlAndSave: (payload: { url: string; targetName: string }) =>
    ApiClient.post<CrawlResultResponse>('/crawler/crawl-and-save', payload),

  batchCrawl: (payload: { targetName: string; urls: string[] }) =>
    ApiClient.post<BatchCrawlResponse>('/crawler/batch-crawl', payload),

  collectPopularResources: (sourceName: string, limit = 10) =>
    ApiClient.post<CollectPopularResponse>(
      `/data-collection/collect-popular/${encodeURIComponent(sourceName)}?limit=${limit}`,
      {},
    ),

  getSourceHealth: () => ApiClient.get<SourceHealthSummary[]>('/data-collection/source-health'),

  getStatistics: () => ApiClient.get<StatisticsResponse>('/data-collection/statistics'),

  updateSourcePolicy: (sourceName: string, payload: SourcePolicyUpdatePayload) =>
    ApiClient.patch<CrawlerTarget>(
      `/data-collection/sources/${encodeURIComponent(sourceName)}/policy`,
      payload,
    ),
};

import axios from 'axios';
import { RequestInterceptor, RetryHelper } from '@/utils/api-helpers';
import { GlobalErrorHandler } from '@/utils/global-error-handler';
import { setupCacheInterceptors, withCache } from '@/utils/api-cache';

// 创建axios实例
const api = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || '/api',
  headers: {
    'Content-Type': 'application/json; charset=utf-8',
    Accept: 'application/json; charset=utf-8',
    // 生产环境安全头
    'X-Requested-With': 'XMLHttpRequest',
  },
  timeout: parseInt(import.meta.env.VITE_API_TIMEOUT) || 30000,
  // 生产环境SSL证书验证
  withCredentials: true,
});

// 应用请求拦截器
const interceptor = RequestInterceptor.config();
api.interceptors.request.use(interceptor.onRequest);
api.interceptors.response.use(interceptor.onResponse, interceptor.onResponseError);

// 应用缓存拦截器
setupCacheInterceptors(api);

// 增强的API客户端
class ApiClient {
  private static instance = api;

  // 带缓存的GET请求
  static async get<T>(url: string, config?: Record<string, any>, useCache = true): Promise<T> {
    if (useCache) {
      // 使用缓存配置
      const cacheConfig = config?.cacheConfig || { enabled: true };
      return this.instance
        .get(url, withCache(config || {}, cacheConfig))
        .then(response => response.data)
        .catch(error => {
          if (error?.cached) {
            // 返回缓存的旧数据
            return error.data;
          }
          GlobalErrorHandler.handle(error, `获取数据失败: ${url}`);
          throw error;
        });
    }

    // 不使用缓存
    return RetryHelper.retry(async () => {
      try {
        const response = await this.instance.get(url, config);
        return response.data;
      } catch (error) {
        GlobalErrorHandler.handle(error, `获取数据失败: ${url}`);
        throw error;
      }
    });
  }

  // POST请求
  static async post<T>(
    url: string,
    data?: Record<string, any>,
    config?: Record<string, any>,
  ): Promise<T> {
    return RetryHelper.retry(async () => {
      try {
        const response = await this.instance.post(url, data, config);

        // POST请求后清除相关缓存
        // CacheManager.clearPattern(/^GET:/);

        return response.data;
      } catch (error) {
        GlobalErrorHandler.handle(error, `POST请求失败: ${url}`);
        throw error;
      }
    });
  }

  // PUT请求
  static async put<T>(
    url: string,
    data?: Record<string, any>,
    config?: Record<string, any>,
  ): Promise<T> {
    return RetryHelper.retry(async () => {
      try {
        const response = await this.instance.put(url, data, config);

        // PUT请求后清除相关缓存
        // CacheManager.clearPattern(/^GET:/);

        return response.data;
      } catch (error) {
        GlobalErrorHandler.handle(error, `PUT请求失败: ${url}`);
        throw error;
      }
    });
  }

  // PATCH请求
  static async patch<T>(
    url: string,
    data?: Record<string, any>,
    config?: Record<string, any>,
  ): Promise<T> {
    return RetryHelper.retry(async () => {
      try {
        const response = await this.instance.patch(url, data, config);

        // PATCH请求后清除相关缓存
        // CacheManager.clearPattern(/^GET:/);

        return response.data;
      } catch (error) {
        GlobalErrorHandler.handle(error, `PATCH请求失败: ${url}`);
        throw error;
      }
    });
  }

  // DELETE请求
  static async delete<T>(url: string, config?: Record<string, any>): Promise<T> {
    return RetryHelper.retry(async () => {
      try {
        const response = await this.instance.delete(url, config);

        // DELETE请求后清除相关缓存
        // CacheManager.clearPattern(/^GET:/);

        return response.data;
      } catch (error) {
        GlobalErrorHandler.handle(error, `DELETE请求失败: ${url}`);
        throw error;
      }
    });
  }

  // 文件上传
  static async upload<T>(
    url: string,
    file: File,
    onProgress?: (progress: number) => void,
  ): Promise<T> {
    const formData = new FormData();
    formData.append('file', file);

    return new Promise((resolve, reject) => {
      RetryHelper.retry(async () => {
        try {
          const response = await this.instance.post(url, formData, {
            onUploadProgress: progressEvent => {
              if (progressEvent.lengthComputable && progressEvent.total) {
                const progress = Math.round((progressEvent.loaded * 100) / progressEvent.total);
                onProgress?.(progress);
              }
            },
            headers: {
              'Content-Type': 'multipart/form-data',
            },
          });

          // 上传后清除相关缓存
          // CacheManager.clearPattern(/^GET:/);

          return response.data;
        } catch (error) {
          GlobalErrorHandler.handle(error, `文件上传失败: ${url}`);
          throw error;
        }
      })
        .then(resolve)
        .catch(reject);
    });
  }

  // 批量请求（并行）
  static async batch<T>(
    requests: Array<{
      method: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';
      url: string;
      data?: Record<string, any>;
      config?: Record<string, any>;
    }>,
  ): Promise<(T | unknown)[]> {
    return Promise.all(
      requests.map(async request => {
        try {
          switch (request.method) {
            case 'GET':
              return await this.get(request.url, request.config);
            case 'POST':
              return await this.post(request.url, request.data, request.config);
            case 'PUT':
              return await this.put(request.url, request.data, request.config);
            case 'PATCH':
              return await this.patch(request.url, request.data, request.config);
            case 'DELETE':
              return await this.delete(request.url, request.config);
            default:
              throw new Error(`Unsupported method: ${request.method}`);
          }
        } catch (error) {
          GlobalErrorHandler.handle(error, `批量请求失败: ${request.method} ${request.url}`);
          return error;
        }
      }),
    );
  }

  // 请求取消令牌
  static cancelToken = axios.CancelToken.source();

  // 取消所有待处理的请求
  static cancelAll() {
    this.cancelToken.cancel('All requests were cancelled');
    this.cancelToken = axios.CancelToken.source();
  }

  // 获取当前请求配置
  static getConfig() {
    return {
      baseURL: this.instance.defaults.baseURL,
      headers: this.instance.defaults.headers,
      timeout: this.instance.defaults.timeout,
    };
  }

  // 更新请求配置
  static updateConfig(config: Record<string, any>) {
    Object.assign(this.instance.defaults, config);
  }
}

// 统一导出各模块 API
export { mediaApi } from './media';
export { playSourceApi } from './playSource';
export { authApi } from './auth';
export { recommendationsApi } from './recommendations';
export { searchApi } from './search';
export { torrentApi } from './torrent';
export { iptvApi } from './iptv';
export { downloadTasksApi } from './downloadTasks';

export default ApiClient;

import ApiClient from './index';
import type { PaginatedResponse } from '@/types/api';
import type { MediaResource, MediaQueryParams, PlaySource } from '@/types/media';
import type { WatchHistoryItem } from './watchHistory';

export const mediaApi = {
  getMediaList: (params?: MediaQueryParams) => {
    return ApiClient.get<PaginatedResponse<MediaResource>>('/media', { params });
  },

  getMediaById: (id: string) => {
    return ApiClient.get<MediaResource>(`/media/${id}`, undefined, false);
  },

  createMedia: (data: any) => {
    return ApiClient.post<MediaResource>('/media', data);
  },

  updateMedia: (id: string, data: any) => {
    return ApiClient.put<MediaResource>(`/media/${id}`, data);
  },

  deleteMedia: (id: string) => {
    return ApiClient.delete<void>(`/media/${id}`);
  },

  searchMedia: (query: string, params?: MediaQueryParams) => {
    return ApiClient.get<PaginatedResponse<MediaResource>>('/media/search', {
      params: { keyword: query, ...params },
    });
  },

  getPopularMedia: (limit?: number, params?: MediaQueryParams) => {
    return ApiClient.get<MediaResource[]>('/media/popular', {
      params: { limit, ...params },
    });
  },

  getLatestMedia: (limit?: number, params?: MediaQueryParams) => {
    return ApiClient.get<MediaResource[]>('/media/latest', {
      params: { limit, ...params },
    });
  },

  getTopRatedMedia: (limit?: number, minRating?: number, params?: MediaQueryParams) => {
    return ApiClient.get<MediaResource[]>('/recommendations/top-rated', {
      params: { limit, minRating, ...params },
    });
  },

  getRecommendedMedia: (params?: MediaQueryParams) => {
    return ApiClient.get<MediaResource[]>('/recommendations/trending', { params });
  },

  getMediaByType: (type: string, params?: MediaQueryParams) => {
    return ApiClient.get<PaginatedResponse<MediaResource>>('/media', {
      params: { ...params, type },
    });
  },

  getSimilarMedia: (mediaId: string | number, limit = 6) => {
    return ApiClient.get<MediaResource[]>(`/media/${mediaId}/similar`, {
      params: { limit },
    });
  },

  getPlaySources: (mediaId: string) => {
    return ApiClient.get<PlaySource[]>(`/play-sources/media/${mediaId}`);
  },

  incrementViewCount: (mediaId: string) => {
    return ApiClient.put<void>(`/media/${mediaId}/views`);
  },

  addFavorite: (mediaId: string) => {
    return ApiClient.post<void>(`/media/${mediaId}/favorites`);
  },

  removeFavorite: (mediaId: string) => {
    return ApiClient.delete<void>(`/media/${mediaId}/favorites`);
  },

  getFavoriteStatus: (mediaId: string) => {
    return ApiClient.get<{ isFavorited: boolean }>(`/media/${mediaId}/favorites/status`, undefined, false);
  },

  toggleFavorite: async (mediaId: string, currentState?: boolean) => {
    const isFavorited =
      typeof currentState === 'boolean'
        ? currentState
        : (await mediaApi.getFavoriteStatus(mediaId)).isFavorited;

    if (isFavorited) {
      await mediaApi.removeFavorite(mediaId);
      return { isFavorited: false };
    }

    await mediaApi.addFavorite(mediaId);
    return { isFavorited: true };
  },

  getFavorites: (params?: MediaQueryParams) => {
