import { ref, reactive } from 'vue'

// 模态框状态
export const modalState = reactive({
  isVisible: false,
  type: 'info' as 'loading' | 'success' | 'error' | 'info' | 'confirm',
  title: '',
  message: '',
  confirmText: '确认',
  cancelText: '取消',
  showAction: false,
  onConfirm: () => {},
  onCancel: () => {},
})

// 显示模态框
export const showModal = (options: {
  type?: 'loading' | 'success' | 'error' | 'info' | 'confirm'
  title?: string
  message?: string
  confirmText?: string
  cancelText?: string
  showAction?: boolean
  onConfirm?: () => void
  onCancel?: () => void
}) => {
  Object.assign(modalState, {
    isVisible: true,
    type: options.type || 'info',
    title: options.title || '',
    message: options.message || '',
    confirmText: options.confirmText || '确认',
    cancelText: options.cancelText || '取消',
    showAction: options.showAction || false,
    onConfirm: options.onConfirm || (() => {}),
    onCancel: options.onCancel || (() => {}),
  })
}

// 隐藏模态框
export const hideModal = () => {
  modalState.isVisible = false
}

// 显示加载中
export const showLoading = (message = '加载中...') => {
  showModal({
    type: 'loading',
    title: '请稍候',
    message,
    showAction: false,
  })
}

// 显示成功
export const showSuccess = (message: string, title = '成功') => {
  showModal({
    type: 'success',
    title,
    message,
    showAction: false,
  })
}

// 显示错误
export const showError = (message: string, title = '错误') => {
  showModal({
    type: 'error',
    title,
    message,
    showAction: false,
  })
}

// 显示信息
export const showInfo = (message: string, title = '提示') => {
  showModal({
    type: 'info',
    title,
    message,
    showAction: false,
  })
}

// 显示确认对话框
export const showConfirm = (
  message: string,
  onConfirm: () => void,
  title = '确认',
  confirmText = '确认',
  cancelText = '取消'
) => {
  showModal({
    type: 'confirm',
    title,
    message,
    confirmText,
    cancelText,
    showAction: true,
    onConfirm,
    onCancel: hideModal,
  })
}

// 通知系统
export interface Notification {
  id: number
  type: 'success' | 'error' | 'warning' | 'info'
  title: string
  message: string
  duration?: number
}

export const notifications = ref<Notification[]>([])

let notificationId = 0

// 显示通知
export const showNotification = (options: {
  type: 'success' | 'error' | 'warning' | 'info'
  title: string
  message: string
  duration?: number
}) => {
  const id = ++notificationId
  const notification: Notification = {
    id,
    type: options.type,
    title: options.title,
    message: options.message,
    duration: options.duration || 5000,
  }
  
  notifications.value.push(notification)
  
  // 自动移除通知
  setTimeout(() => {
    removeNotification(id)
  }, notification.duration)
}

// 移除通知
export const removeNotification = (id: number) => {
  const index = notifications.value.findIndex(n => n.id === id)
  if (index > -1) {
    notifications.value.splice(index, 1)
  }
}

// 快捷方法
export const notifySuccess = (title: string, message: string) => {
  showNotification({ type: 'success', title, message })
}

export const notifyError = (title: string, message: string) => {
  showNotification({ type: 'error', title, message })
}

export const notifyWarning = (title: string, message: string) => {
  showNotification({ type: 'warning', title, message })
}

export const notifyInfo = (title: string, message: string) => {
  showNotification({ type: 'info', title, message })
}

import { ref } from 'vue';

export type PageNoticeType = 'success' | 'error' | 'warning' | 'info';

export interface PageNoticeState {
  type: PageNoticeType;
  message: string;
  title?: string;
}

export const usePageNotice = () => {
  const notice = ref<PageNoticeState | null>(null);

  const setNotice = (type: PageNoticeType, message: string, title?: string) => {
    notice.value = { type, message, title };
  };

  const clearNotice = () => {
    notice.value = null;
  };

  return {
    notice,
    setNotice,
    clearNotice,
  };
};

/**
 * 代码分割和懒加载服务
 */

// 路由定义类型
export interface RouteDefinition {
  path: string;
  name?: string;
  component?: () => Promise<any>;
  children?: RouteDefinition[];
  meta?: Record<string, any>;
}

// 模块加载策略
export interface LoadingStrategy {
  strategy: 'eager' | 'lazy' | 'preload' | 'prefetch';
  priority: 'high' | 'medium' | 'low';
  timeout?: number;
  retryCount?: number;
  fallback?: () => Promise<any>;
}

// 模块信息
export interface ModuleInfo {
  name: string;
  path: string;
  size?: number;
  dependencies?: string[];
  strategy: LoadingStrategy;
  loaded: boolean;
  loading: boolean;
  error?: string;
  loadTime?: number;
}

// 预加载配置
export interface PreloadConfig {
  enabled: boolean;
  strategy: 'onLoad' | 'onIdle' | 'onInteraction' | 'network';
  concurrency: number;
  timeout: number;
  retryCount: number;
}

export class CodeSplitService {
  private static instance: CodeSplitService;
  private modules: Map<string, ModuleInfo> = new Map();
  private loadingQueue: Map<string, Promise<any>> = new Map();
  private preloadQueue: string[] = [];
  private config: PreloadConfig;
  private observers: IntersectionObserver[] = [];

  constructor(config: Partial<PreloadConfig> = {}) {
    this.config = {
      enabled: true,
      strategy: 'onIdle',
      concurrency: 3,
      timeout: 10000,
      retryCount: 3,
      ...config,
    };

    this.init();
  }

  static getInstance(config?: Partial<PreloadConfig>): CodeSplitService {
    if (!CodeSplitService.instance) {
      CodeSplitService.instance = new CodeSplitService(config);
    }
    return CodeSplitService.instance;
  }

  private init() {
    if (typeof window === 'undefined') return;

    this.setupIntersectionObserver();
    this.setupNetworkListener();
    this.startPreloading();
  }

  // 注册模块
  registerModule(name: string, loader: () => Promise<any>, strategy: LoadingStrategy) {
    const moduleInfo: ModuleInfo = {
      name,
      path: name,
      strategy,
      loaded: false,
      loading: false,
    };

    this.modules.set(name, moduleInfo);

    // 根据策略立即加载
    if (strategy.strategy === 'eager') {
      this.loadModule(name);
    } else if (strategy.strategy === 'preload') {
      this.addToPreloadQueue(name);
    }
  }

  // 加载模块
  async loadModule(name: string): Promise<any> {
    const module = this.modules.get(name);
    if (!module) {
      throw new Error(`Module ${name} not found`);
    }

    // 如果已经加载，直接返回
    if (module.loaded) {
      return this.getLoadedModule(name);
    }

    // 如果正在加载，返回现有Promise
    if (this.loadingQueue.has(name)) {
      return this.loadingQueue.get(name);
    }

    // 开始加载
    module.loading = true;
    const startTime = Date.now();

    const loadPromise = this.loadWithRetry(name)
      .then(result => {
        module.loaded = true;
        module.loading = false;
        module.loadTime = Date.now() - startTime;
        module.error = undefined;

        // 记录性能指标
        this.recordLoadMetrics(module);

        // 清理队列
        this.loadingQueue.delete(name);

        return result;
      })
      .catch(error => {
        module.loading = false;
        module.error = error.message;

        // 清理队列
        this.loadingQueue.delete(name);

        // 尝试使用fallback
        if (module.strategy.fallback) {
          return module.strategy.fallback();
        }

        throw error;
      });

    this.loadingQueue.set(name, loadPromise);
    return loadPromise;
  }

  // 带重试的加载
  private async loadWithRetry(name: string, retryCount = 0): Promise<any> {
    const module = this.modules.get(name);
    if (!module) {
      throw new Error(`Module ${name} not found`);
    }

    try {
      // 模拟动态导入
      const startTime = Date.now();
      const result = await Promise.race([
        this.simulateDynamicImport(name),
        this.createTimeout(module.strategy.timeout || this.config.timeout),
      ]);

      const loadTime = Date.now() - startTime;
      console.log(`Module ${name} loaded in ${loadTime}ms`);

      return result;
    } catch (error) {
      if (retryCount < (module.strategy.retryCount || this.config.retryCount)) {
        console.warn(`Retrying module ${name}, attempt ${retryCount + 1}`);
        return this.loadWithRetry(name, retryCount + 1);
      }
      throw error;
    }
  }

  // 模拟动态导入
  private async simulateDynamicImport(name: string): Promise<any> {
    // 这里应该是实际的动态导入逻辑
    // 由于我们是在创建服务，这里返回一个模拟的Promise

    // 实际使用时，这里应该是：
    // return import(`@/views/${name}.vue`)

    // 为了演示，我们返回一个模拟的模块
    return new Promise(resolve => {
      setTimeout(
        () => {
          resolve({
            default: () => `Module ${name} component`,
            name,
          });
        },
        Math.random() * 500 + 100,
      ); // 模拟网络延迟
    });
  }

  // 创建超时
  private createTimeout(timeout: number): Promise<never> {
    return new Promise((_, reject) => {
      setTimeout(() => {
        reject(new Error(`Module load timeout after ${timeout}ms`));
      }, timeout);
    });
  }

  // 获取已加载的模块
  private getLoadedModule(name: string): Promise<any> {
    // 这里应该从已加载的模块缓存中获取
    // 由于是演示，我们重新模拟加载
    return this.simulateDynamicImport(name);
  }

  // 添加到预加载队列
  private addToPreloadQueue(name: string) {
    if (!this.preloadQueue.includes(name)) {
      this.preloadQueue.push(name);
    }
  }

  // 开始预加载
  private startPreloading() {
    if (!this.config.enabled) return;

    switch (this.config.strategy) {
      case 'onLoad':
        this.preloadOnLoad();
        break;
      case 'onIdle':
        this.preloadOnIdle();
        break;
      case 'onInteraction':
        this.preloadOnInteraction();
        break;
      case 'network':
        this.preloadOnNetwork();
        break;
    }
  }

  // 页面加载时预加载
  private preloadOnLoad() {
    setTimeout(() => {
      this.processPreloadQueue();
    }, 1000);
  }

  // 空闲时预加载
  private preloadOnIdle() {
    if ('requestIdleCallback' in window) {
      (window as any).requestIdleCallback(
        () => {
          this.processPreloadQueue();
        },
        { timeout: 2000 },
      );
    } else {
      setTimeout(() => {
        this.processPreloadQueue();
      }, 2000);
    }
  }

  // 交互时预加载
  private preloadOnInteraction() {
    const events = ['mousemove', 'touchstart', 'keydown', 'click'];
    let triggered = false;

    const handler = () => {
      if (triggered) return;
      triggered = true;
      this.processPreloadQueue();
      events.forEach(event => {
        window.removeEventListener(event, handler);
      });
    };

    events.forEach(event => {
      window.addEventListener(event, handler, { once: true });
    });
  }

  // 网络空闲时预加载
  private preloadOnNetwork() {
    if ('connection' in navigator) {
      const connection = (navigator as any).connection;
      if (connection.effectiveType === '4g' && !connection.saveData) {
        this.processPreloadQueue();
      } else {
        connection.addEventListener('change', () => {
          if (connection.effectiveType === '4g' && !connection.saveData) {
            this.processPreloadQueue();
          }
        });
      }
    } else {
      // 如果不支持Network Information API，使用默认策略
      this.preloadOnIdle();
    }
  }

  // 处理预加载队列
  private async processPreloadQueue() {
    const queue = [...this.preloadQueue];
    this.preloadQueue = [];

    // 按优先级排序
    queue.sort((a, b) => {
      const moduleA = this.modules.get(a);
      const moduleB = this.modules.get(b);
      if (!moduleA || !moduleB) return 0;

      const priorityA =
        moduleA.strategy.priority === 'high' ? 3 : moduleA.strategy.priority === 'medium' ? 2 : 1;
      const priorityB =
        moduleB.strategy.priority === 'high' ? 3 : moduleB.strategy.priority === 'medium' ? 2 : 1;

      return priorityB - priorityA;
    });

    // 并发加载
    const concurrency = this.config.concurrency;
    for (let i = 0; i < queue.length; i += concurrency) {
      const batch = queue.slice(i, i + concurrency);
      await Promise.allSettled(
        batch.map(name =>
          this.loadModule(name).catch(error => {
            console.warn(`Failed to preload module ${name}:`, error);
          }),
        ),
      );

      // 批次间隔
      if (i + concurrency < queue.length) {
        await new Promise(resolve => setTimeout(resolve, 100));
      }
    }
  }

  // 设置交叉观察器
  private setupIntersectionObserver() {
    if (typeof IntersectionObserver === 'undefined') return;

    const observer = new IntersectionObserver(
      entries => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const element = entry.target as HTMLElement;
            const moduleName = element.dataset.module;
            if (moduleName) {
              this.addToPreloadQueue(moduleName);
              observer.unobserve(element);
            }
          }
        });
      },
      {
        rootMargin: '100px',
        threshold: 0.1,
      },
    );

    this.observers.push(observer);
  }

  // 设置网络监听器
  private setupNetworkListener() {
    if ('connection' in navigator) {
      const connection = (navigator as any).connection;
      connection.addEventListener('change', () => {
        // 网络条件变化时，调整预加载策略
        if (connection.saveData) {
          // 数据节省模式，停止预加载
          this.preloadQueue = [];
        } else if (connection.effectiveType === '4g') {
          // 高速网络，增加并发
          this.config.concurrency = Math.min(6, this.config.concurrency + 1);
        } else {
          // 低速网络，减少并发
          this.config.concurrency = Math.max(1, this.config.concurrency - 1);
        }
      });
    }
  }

  // 记录加载指标
  private recordLoadMetrics(module: ModuleInfo) {
    if (!module.loadTime) return;

    const metrics = {
      name: module.name,
      loadTime: module.loadTime,
      strategy: module.strategy.strategy,
      timestamp: Date.now(),
      userAgent: navigator.userAgent,
    };

    // 发送到分析服务
    if (typeof console === 'object' && console.log) {
      console.log('Module load metrics:', metrics);
    }

    // 这里可以发送到实际的分析服务
    // this.sendToAnalytics(metrics);
  }

  // 获取模块状态
  getModuleStatus(name: string): ModuleInfo | undefined {
    return this.modules.get(name);
  }

  // 获取所有模块状态
  getAllModuleStatus(): ModuleInfo[] {
    return Array.from(this.modules.values());
  }

  // 手动触发预加载
  async preloadModules(names: string[]): Promise<void> {
    const uniqueNames = [...new Set(names)];
    this.preloadQueue.push(...uniqueNames);
    await this.processPreloadQueue();
  }

  // 取消预加载
  cancelPreload(name: string) {
    const index = this.preloadQueue.indexOf(name);
    if (index > -1) {
      this.preloadQueue.splice(index, 1);
    }
  }

  // 检查模块是否已加载
  isModuleLoaded(name: string): boolean {
    const module = this.modules.get(name);
    return module?.loaded || false;
  }

  // 获取加载统计
  getLoadStats() {
    const modules = Array.from(this.modules.values());
    const loadedCount = modules.filter(m => m.loaded).length;
    const loadingCount = modules.filter(m => m.loading).length;
    const errorCount = modules.filter(m => m.error).length;
    const totalLoadTime = modules
      .filter(m => m.loadTime)
      .reduce((sum, m) => sum + (m.loadTime || 0), 0);
    const avgLoadTime = loadedCount > 0 ? totalLoadTime / loadedCount : 0;

    return {
      total: modules.length,
      loaded: loadedCount,
      loading: loadingCount,
      errors: errorCount,
      avgLoadTime: Math.round(avgLoadTime),
    };
  }

  // 创建路由定义的助手方法
  createRoute(
    path: string,
    name: string,
    component: () => Promise<any>,
    strategy: LoadingStrategy = { strategy: 'lazy', priority: 'medium' },
  ): RouteDefinition {
    // 注册模块
    this.registerModule(name, component, strategy);

    return {
      path,
      name,
      component,
      meta: {
        preload: strategy.strategy === 'preload',
        eager: strategy.strategy === 'eager',
      },
    };
  }

  // 创建嵌套路由的助手方法
  createNestedRoute(
    path: string,
    name: string,
    component: () => Promise<any>,
    children: RouteDefinition[],
    strategy: LoadingStrategy = { strategy: 'lazy', priority: 'medium' },
  ): RouteDefinition {
    this.registerModule(name, component, strategy);

    return {
      path,
      name,
      component,
      children,
      meta: {
        preload: strategy.strategy === 'preload',
        eager: strategy.strategy === 'eager',
      },
    };
  }

  // 销毁
  destroy() {
    this.observers.forEach(observer => observer.disconnect());
    this.observers = [];
    this.modules.clear();
    this.loadingQueue.clear();
    this.preloadQueue = [];
    CodeSplitService.instance = null as any;
  }
}

// 创建单例实例
export const codeSplitService = CodeSplitService.getInstance();

// 导出助手函数
export function createLazyRoute(
  path: string,
  name: string,
  component: () => Promise<any>,
  strategy: LoadingStrategy = { strategy: 'lazy', priority: 'medium' },
): RouteDefinition {
  return codeSplitService.createRoute(path, name, component, strategy);
}

export function createLazyNestedRoute(
  path: string,
  name: string,
  component: () => Promise<any>,
  children: RouteDefinition[],
  strategy: LoadingStrategy = { strategy: 'lazy', priority: 'medium' },
): RouteDefinition {
  return codeSplitService.createNestedRoute(path, name, component, children, strategy);
}

export function preloadModules(names: string[]): Promise<void> {
  return codeSplitService.preloadModules(names);
}

export function getModuleStatus(name: string): ModuleInfo | undefined {
  return codeSplitService.getModuleStatus(name);
}

import { ref, reactive, onUnmounted, onMounted } from 'vue';
import io from 'socket.io-client';
type Socket = any;
import { useAuthStore } from '@/stores/auth';
import type {
  DanmakuMessage,
  RoomInfo,
  HeartbeatResponse,
  DanmakuSettings,
  DanmakuServiceConfig,
} from '@/types/danmaku';

const DEV = import.meta.env.DEV;

export type {
  DanmakuMessage,
  RoomInfo,
  HeartbeatResponse,
  DanmakuSettings,
  DanmakuServiceConfig,
};

// WebSocket服务类
export class DanmakuWebSocketService {
  private socket: Socket | null = null;
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;
  private reconnectInterval: number;
  private heartbeatInterval: number | null = null;
  private isConnected = ref(false);
  private roomId = ref('');
  private userId = ref('');

  // 事件监听器
  private listeners = new Map<string, Set<Function>>();

  // 消息队列（在重连时暂存）
  private messageQueue: any[] = [];

  // 配置选项
  private options = {
    reconnectDelay: 1000,
    heartbeatInterval: 30000,
    maxQueueSize: 100,
    autoReconnect: true,
  };

  constructor(private authStore: any) {}

  // 连接WebSocket
  connect(videoId: string, userId: string) {
    try {
      this.roomId.value = videoId;
      this.userId.value = userId;

      const config: DanmakuServiceConfig = {
        serverUrl: (import.meta.env.VITE_WS_URL || 'ws://localhost:3334') + '/danmaku',
        reconnectDelay: this.options.reconnectDelay,
        heartbeatInterval: this.options.heartbeatInterval,
        maxQueueSize: this.options.maxQueueSize,
        autoReconnect: this.options.autoReconnect,
        maxReconnectAttempts: this.maxReconnectAttempts,
      };

      this.socket = io(config.serverUrl, {
        auth: {
          token: this.authStore.token,
          videoId,
          userId,
        },
        transports: ['websocket', 'polling'],
        timeout: 10000,
        reconnection: true,
        reconnectionAttempts: config.maxReconnectAttempts,
        reconnectionDelay: config.reconnectDelay,
      });

      this.setupEventHandlers();
    } catch (error) {
      console.error('❌ WebSocket连接失败:', error);
      this.handleConnectionError(error);
    }
  }

  // 设置事件处理器
  private setupEventHandlers() {
    if (!this.socket) return;

    // 连接成功
    this.socket.on('connect', () => {
      if (DEV) {
        console.log('[DanmakuWS] connected');
      }
      this.isConnected.value = true;
      this.reconnectAttempts = 0;

      // 加入房间
      this.socket?.emit('join-room', {
        videoId: this.roomId.value,
        userId: this.userId.value,
      });

      // 发送队列中的消息
      this.flushMessageQueue();

      // 开始心跳
      this.startHeartbeat();

      // 触发连接成功事件
      this.emit('connected');
    });

    // 连接断开
    this.socket.on('disconnect', reason => {
      if (DEV) {
        console.log('[DanmakuWS] disconnected:', reason);
      }
      this.isConnected.value = false;
      this.stopHeartbeat();
      this.emit('disconnected', reason);

      // 自动重连
      if (this.options.autoReconnect && reason !== 'io client disconnect') {
        this.handleReconnect();
      }
    });

    // 连接错误
    this.socket.on('connect_error', error => {
      console.error('❌ WebSocket连接错误:', error);
      this.handleConnectionError(error);
    });

    // 接收弹幕消息
    this.socket.on('danmaku-message', (message: DanmakuMessage) => {
      this.emit('message', message);
    });

    // 接收房间信息
    this.socket.on('room-info', (info: RoomInfo) => {
      this.emit('room-info', info);
    });

    // 心跳响应
    this.socket.on('heartbeat-response', (response: HeartbeatResponse) => {
      this.emit('heartbeat', response);
    });

    // 错误消息
    this.socket.on('error', error => {
      console.error('❌ WebSocket错误:', error);
      this.emit('error', error);
    });
  }

  // 发送弹幕消息
  sendDanmaku(message: Omit<DanmakuMessage, 'id' | 'timestamp'>) {
    if (!this.isConnected.value || !this.socket) {
      // 添加到消息队列
      this.addToMessageQueue({
        event: 'send-danmaku',
        data: message,
      });
      return;
    }

    this.socket.emit('send-danmaku', {
      ...message,
      videoId: this.roomId.value,
      userId: this.userId.value,
      timestamp: Date.now(),
      id: this.generateMessageId(),
    });
  }

  // 获取房间信息
  getRoomInfo() {
    if (!this.isConnected.value || !this.socket) return;

    this.socket.emit('get-room-info', {
      videoId: this.roomId.value,
    });
  }

  // 心跳检测
  private startHeartbeat() {
    this.stopHeartbeat();

    this.heartbeatInterval = window.setInterval(() => {
      if (this.isConnected.value && this.socket) {
        this.socket.emit('heartbeat', {
          userId: this.userId.value,
          timestamp: Date.now(),
        });
      }
    }, this.options.heartbeatInterval);
  }

  private stopHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
  }

  // 重连处理
  private handleReconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      if (DEV) {
        console.warn('[DanmakuWS] reached max reconnect attempts');
      }
      this.emit('reconnect-failed');
      return;
    }

    this.reconnectAttempts++;
    if (DEV) {
      console.log(
        `[DanmakuWS] reconnecting (${this.reconnectAttempts}/${this.maxReconnectAttempts})`,
      );
    }

    this.reconnectInterval = window.setTimeout(() => {
      if (this.roomId.value && this.userId.value) {
        this.connect(this.roomId.value, this.userId.value);
      }
    }, this.options.reconnectDelay * this.reconnectAttempts);
  }

  // 连接错误处理
  private handleConnectionError(error: any) {
    this.isConnected.value = false;
    this.emit('error', error);

    // 如果启用了自动重连，尝试重连
    if (this.options.autoReconnect) {
      this.handleReconnect();
    }
  }

  // 消息队列管理
  private addToMessageQueue(message: any) {
    if (this.messageQueue.length >= this.options.maxQueueSize) {
      // 队列满，移除最旧的消息
      this.messageQueue.shift();
    }
    this.messageQueue.push(message);
  }

  private flushMessageQueue() {
    if (!this.isConnected.value || !this.socket) return;

    const messages = [...this.messageQueue];
    this.messageQueue = [];

    messages.forEach(message => {
      switch (message.event) {
        case 'send-danmaku':
          this.sendDanmaku(message.data);
          break;
        // 其他消息类型处理
      }
    });
  }

  // 事件管理
  on(event: string, callback: Function) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(callback);
  }

  off(event: string, callback: Function) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      callbacks.delete(callback);
    }
  }

  private emit(event: string, ...args: any[]) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      callbacks.forEach(callback => {
        try {
          callback(...args);
        } catch (error) {
          console.error('❌ 事件回调执行错误:', error);
        }
      });
    }
  }

  // 工具方法
  private generateMessageId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  // 状态获取
  get connected(): boolean {
    return this.isConnected.value;
  }

  get currentRoomId(): string {
    return this.roomId.value;
  }

  get currentUserId(): string {
    return this.userId.value;
  }

  // 断开连接
  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
    }

    this.stopHeartbeat();
    this.isConnected.value = false;
    this.reconnectAttempts = 0;
    this.messageQueue = [];

    // 清理事件监听器
    this.listeners.clear();

    // 清理重连定时器
    if (this.reconnectInterval) {
      clearTimeout(this.reconnectInterval);
      this.reconnectInterval = 0;
    }
  }

  // 销毁服务
  destroy() {
    this.disconnect();
  }
}

// 创建全局服务实例
let danmakuService: DanmakuWebSocketService | null = null;

/**
 * 初始化弹幕WebSocket服务
 */
export function initDanmakuService(authStore: any): DanmakuWebSocketService {
  if (!danmakuService) {
    danmakuService = new DanmakuWebSocketService(authStore);
  }
  return danmakuService;
}

/**
 * 获取弹幕服务实例
 */
export function getDanmakuService(): DanmakuWebSocketService | null {
  return danmakuService;
}

// Vue组合式API弹幕服务集成
export function useDanmakuWebSocket(videoId: string) {
  const authStore = useAuthStore();
  const service = initDanmakuService(authStore);
  const isConnected = ref(false);
  const roomInfo = ref<RoomInfo | null>(null);

  // 连接管理
  const connect = () => {
    if (authStore.user?.id && videoId) {
      service.connect(videoId, authStore.user.id.toString());
    }
  };

  // 断开连接
  const disconnect = () => {
    service.disconnect();
  };

  // 发送弹幕
  const sendDanmaku = (message: Omit<DanmakuMessage, 'id' | 'timestamp'>) => {
    return service.sendDanmaku(message);
  };

  // 获取房间信息
  const getRoomInfo = () => {
    service.getRoomInfo();
  };

  // 事件监听
  const onDanmaku = (callback: (message: DanmakuMessage) => void) => {
    service.on('danmaku-message', callback);
  };

  const onSystem = (callback: (message: DanmakuMessage) => void) => {
    service.on('system-message', callback);
  };

  const onRoomInfo = (callback: (info: RoomInfo) => void) => {
    service.on('room-info', callback);
  };

  const onConnected = (callback: () => void) => {
    service.on('connected', callback);
  };

  const onDisconnected = (callback: (reason: string) => void) => {
    service.on('disconnected', callback);
  };

  const onError = (callback: (error: any) => void) => {
    service.on('error', callback);
  };

  const onHeartbeat = (callback: (response: HeartbeatResponse) => void) => {
    service.on('heartbeat-response', callback);
  };

  // 设置事件监听器
  onMounted(() => {
    connect();
    service.on('connected', () => (isConnected.value = true));
    service.on('disconnected', () => (isConnected.value = false));
  });

  onUnmounted(() => {
    disconnect();
  });

  return {
    isConnected,
    roomInfo,
    connect,
    disconnect,
    sendDanmaku,
    getRoomInfo,
    onDanmaku,
    onSystem,
    onRoomInfo,
    onConnected,
    onDisconnected,
    onError,
    onHeartbeat,
  };
}

/**
 * 性能监控和优化服务
 */

const DEV = import.meta.env.DEV;

// 性能指标类型定义
export interface PerformanceMetrics {
  // 核心Web指标
  fcp: number; // First Contentful Paint (首次内容绘制)
  lcp: number; // Largest Contentful Paint (最大内容绘制)
  fid: number; // First Input Delay (首次输入延迟)
  cls: number; // Cumulative Layout Shift (累积布局偏移)
  ttfb: number; // Time to First Byte (首字节时间)

  // 加载性能
  pageLoad: number; // 页面加载时间
  domReady: number; // DOM准备就绪时间
  windowLoad: number; // 窗口加载完成时间
  resourceLoad: number; // 资源加载时间

  // 内存使用
  memory: {
    used: number;
    total: number;
    limit: number;
    percentage: number;
  };

  // 网络信息
  network: {
    downlink: number;
    rtt: number;
    effectiveType: string;
    saveData: boolean;
    online: boolean;
  };

  // 设备信息
  device: {
    userAgent: string;
    platform: string;
    cores: number;
    memory: number;
    screen: {
      width: number;
      height: number;
      colorDepth: number;
    };
  };

  // 时间戳
  timestamp: number;
  url: string;
}

// 性能配置
export interface PerformanceConfig {
  // 监控配置
  monitor: {
    enabled: boolean;
    interval: number; // 监控间隔（毫秒）
    metrics: string[]; // 要监控的指标
  };

  // 报告配置
  reporting: {
    enabled: boolean;
    endpoint?: string;
    batchSize: number;
    flushInterval: number;
  };

  // 优化配置
  optimization: {
    lazyLoad: boolean;
    preLoad: boolean;
    cache: boolean;
    compress: boolean;
  };
}

// 性能阈值
export const PERFORMANCE_THRESHOLDS = {
  FCP: 2000, // 2秒
  LCP: 2500, // 2.5秒
  FID: 100, // 100毫秒
  CLS: 0.1, // 0.1
  TTFB: 600, // 600毫秒
  PAGE_LOAD: 3000, // 3秒
  DOM_READY: 1000, // 1秒
};

export class PerformanceService {
  private static instance: PerformanceService;
  private metrics: PerformanceMetrics | null = null;
  private config: PerformanceConfig;
  private observers: PerformanceObserver[] = [];
  private metricBuffer: PerformanceMetrics[] = [];

  constructor(config: Partial<PerformanceConfig> = {}) {
    this.config = {
      monitor: {
        enabled: true,
        interval: 5000,
        metrics: ['fcp', 'lcp', 'fid', 'cls', 'ttfb'],
      },
      reporting: {
        enabled: false,
        batchSize: 10,
        flushInterval: 60000,
      },
      optimization: {
        lazyLoad: true,
        preLoad: true,
        cache: true,
        compress: true,
      },
      ...config,
    };

    this.init();
  }

  static getInstance(config?: Partial<PerformanceConfig>): PerformanceService {
    if (!PerformanceService.instance) {
      PerformanceService.instance = new PerformanceService(config);
    }
    return PerformanceService.instance;
  }

  private init() {
    if (typeof window === 'undefined' || !('performance' in window)) {
      if (DEV) {
        console.warn('Performance API not supported');
      }
      return;
    }

    this.setupObservers();
    this.startMonitoring();
    this.setupEventListeners();
    this.initOptimizations();
  }

  // 设置性能观察器
  private setupObservers() {
    if (!('PerformanceObserver' in window)) {
      if (DEV) {
        console.warn('PerformanceObserver not supported');
      }
      return;
    }

    // 观察LCP
    try {
      const lcpObserver = new PerformanceObserver(entryList => {
        const entries = entryList.getEntries();
        const lastEntry = entries[entries.length - 1];
        if (lastEntry) {
          this.updateMetrics({ lcp: lastEntry.startTime });
        }
      });
      lcpObserver.observe({ entryTypes: ['largest-contentful-paint'] });
      this.observers.push(lcpObserver);
    } catch (e) {
      if (DEV) {
        console.warn('Failed to observe LCP:', e);
      }
    }

    // 观察CLS
    try {
      const clsObserver = new PerformanceObserver(entryList => {
        const entries = entryList.getEntries();
        let clsValue = 0;
        entries.forEach(entry => {
          if (entry && (entry as any).hadRecentInput) {
            return;
          }
          clsValue += (entry as any).value || 0;
        });
        this.updateMetrics({ cls: clsValue });
      });
      clsObserver.observe({ entryTypes: ['layout-shift'] });
      this.observers.push(clsObserver);
    } catch (e) {
      if (DEV) {
        console.warn('Failed to observe CLS:', e);
      }
    }

    // 观察FID
    try {
      const fidObserver = new PerformanceObserver(entryList => {
        const entries = entryList.getEntries();
        entries.forEach(entry => {
          if (entry.name === 'first-input') {
            const fid = (entry as any).processingStart - entry.startTime;
            this.updateMetrics({ fid });
          }
        });
      });
      fidObserver.observe({ entryTypes: ['first-input'] });
      this.observers.push(fidObserver);
    } catch (e) {
      if (DEV) {
        console.warn('Failed to observe FID:', e);
      }
    }

    // 观察资源加载
    try {
      const resourceObserver = new PerformanceObserver(entryList => {
        const entries = entryList.getEntries();
        const resourceLoad = entries.reduce((sum, entry) => sum + entry.duration, 0);
        this.updateMetrics({ resourceLoad: resourceLoad });
      });
      resourceObserver.observe({ entryTypes: ['resource'] });
      this.observers.push(resourceObserver);
    } catch (e) {
      if (DEV) {
        console.warn('Failed to observe resources:', e);
      }
    }
  }

  // 设置事件监听器
  private setupEventListeners() {
    // 页面加载时间
    window.addEventListener('load', () => {
      setTimeout(() => {
        const nav = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
        if (nav) {
          this.updateMetrics({
            ttfb: nav.responseStart - nav.requestStart,
            pageLoad: nav.loadEventEnd - nav.loadEventStart,
          });
        }
      }, 0);
    });

    // DOM准备就绪
    document.addEventListener('DOMContentLoaded', () => {
      const nav = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
      if (nav) {
        this.updateMetrics({ domReady: nav.domContentLoadedEventStart - nav.startTime });
      }
    });

    // 网络状态变化
    if ('connection' in navigator) {
      const connection = (navigator as any).connection;
      connection.addEventListener('change', () => {
        this.updateNetworkInfo();
      });
    }

    // 内存使用
    this.startMemoryMonitoring();
  }

  // 开始监控
  private startMonitoring() {
    if (!this.config.monitor.enabled) return;

    setInterval(() => {
      this.collectMetrics();
    }, this.config.monitor.interval);
  }

  // 收集指标
  private collectMetrics() {
    // 收集FCP
    const paintEntries = performance.getEntriesByType('paint');
    const fcpEntry = paintEntries.find(entry => entry.name === 'first-contentful-paint');
    if (fcpEntry) {
      this.updateMetrics({ fcp: fcpEntry.startTime });
    }

    // 更新网络和设备信息
    this.updateNetworkInfo();
    this.updateDeviceMetrics();
    this.updateMemoryMetrics();
  }

  // 更新指标
  private updateMetrics(updates: Partial<PerformanceMetrics>) {
    if (!this.metrics) {
      this.metrics = this.createEmptyMetrics();
    }

    const updatedMetrics = { ...this.metrics, ...updates, timestamp: Date.now() };
    this.metrics = updatedMetrics;

    // 缓存指标
    this.metricBuffer.push({ ...updatedMetrics });

    // 检查阈值
    this.checkThresholds(updatedMetrics);

    // 报告指标
    if (this.config.reporting.enabled) {
      this.maybeFlushBuffer();
    }
  }

  // 创建空指标
  private createEmptyMetrics(): PerformanceMetrics {
    return {
      fcp: 0,
      lcp: 0,
      fid: 0,
      cls: 0,
      ttfb: 0,
      pageLoad: 0,
      domReady: 0,
      windowLoad: 0,
      resourceLoad: 0,
      memory: {
        used: 0,
        total: 0,
        limit: 0,
        percentage: 0,
      },
      network: {
        downlink: 0,
        rtt: 0,
        effectiveType: '',
        saveData: false,
        online: navigator.onLine,
      },
      device: {
        userAgent: navigator.userAgent,
        platform: navigator.platform,
        cores: 0,
        memory: 0,
        screen: {
          width: window.screen.width,
          height: window.screen.height,
          colorDepth: window.screen.colorDepth,
        },
      },
      timestamp: Date.now(),
      url: window.location.href,
    };
  }

  // 更新网络信息
  private updateNetworkInfo() {
    if (!this.metrics || !('connection' in navigator)) return;

    const connection = (navigator as any).connection;
    this.metrics.network = {
      downlink: connection.downlink || 0,
      rtt: connection.rtt || 0,
      effectiveType: connection.effectiveType || '',
      saveData: connection.saveData || false,
      online: navigator.onLine,
    };
  }

  // 更新设备指标
  private updateDeviceMetrics() {
    if (!this.metrics) return;

    this.metrics.device.screen = {
      width: window.screen.width,
      height: window.screen.height,
      colorDepth: window.screen.colorDepth,
    };
  }

  // 更新内存指标
  private updateMemoryMetrics() {
    if (!this.metrics || !('memory' in performance)) return;

    const memory = (performance as any).memory;
    this.metrics.memory = {
      used: memory.usedJSHeapSize,
      total: memory.totalJSHeapSize,
      limit: memory.jsHeapSizeLimit,
      percentage: (memory.usedJSHeapSize / memory.jsHeapSizeLimit) * 100,
    };
  }

  // 开始内存监控
  private startMemoryMonitoring() {
    if (!('memory' in performance)) return;

    setInterval(() => {
      this.updateMemoryMetrics();

      // 内存警告
      if (this.metrics && this.metrics.memory.percentage > 90) {
        if (DEV) {
          console.warn('Memory usage high:', this.metrics.memory.percentage.toFixed(2) + '%');
        }
        this.optimizeMemory();
      }
    }, 10000); // 每10秒检查一次
  }

  // 内存优化
  private optimizeMemory() {
    // 清理事件监听器
    if ('clearEventListeners' in window) {
      (window as any).clearEventListeners();
    }

    // 触发垃圾回收（如果支持）
    if ('gc' in window) {
      (window as any).gc();
    }

    // 清理不必要的数据
    if (this.metricBuffer.length > 50) {
      this.metricBuffer = this.metricBuffer.slice(-20);
    }
  }

  // 检查性能阈值
  private checkThresholds(metrics: PerformanceMetrics) {
    const warnings = [];

    if (metrics.fcp > PERFORMANCE_THRESHOLDS.FCP) {
      warnings.push(`FCP too high: ${metrics.fcp.toFixed(2)}ms`);
    }
    if (metrics.lcp > PERFORMANCE_THRESHOLDS.LCP) {
      warnings.push(`LCP too high: ${metrics.lcp.toFixed(2)}ms`);
    }
    if (metrics.fid > PERFORMANCE_THRESHOLDS.FID) {
      warnings.push(`FID too high: ${metrics.fid.toFixed(2)}ms`);
    }
    if (metrics.cls > PERFORMANCE_THRESHOLDS.CLS) {
      warnings.push(`CLS too high: ${metrics.cls.toFixed(3)}`);
    }
    if (metrics.ttfb > PERFORMANCE_THRESHOLDS.TTFB) {
      warnings.push(`TTFB too high: ${metrics.ttfb.toFixed(2)}ms`);
    }

    if (warnings.length > 0) {
      if (DEV) {
        console.warn('Performance warnings:', warnings);
      }
      this.reportWarnings(warnings);
    }
  }

  // 报告警告
  private reportWarnings(warnings: string[]) {
    if (typeof console.warn === 'function') {
      if (DEV) {
        console.warn('Performance issues detected:', warnings.join(', '));
      }
    }

    // 这里可以发送到错误监控服务
    // this.sendToErrorService(warnings);
  }

  // 初始化优化
  private initOptimizations() {
    if (this.config.optimization.lazyLoad) {
      this.setupLazyLoading();
    }

    if (this.config.optimization.preLoad) {
      this.setupPreloading();
    }

    if (this.config.optimization.cache) {
      this.setupCaching();
    }
  }

  // 设置懒加载
  private setupLazyLoading() {
    // 为图片和iframe添加懒加载
    const elements = document.querySelectorAll('img[data-src], iframe[data-src]');
    const imageObserver = new IntersectionObserver(
      entries => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const element = entry.target as HTMLElement;
            const src = element.getAttribute('data-src');
            if (src) {
              element.setAttribute('src', src);
              element.removeAttribute('data-src');
              imageObserver.unobserve(element);
            }
          }
        });
      },
      {
        rootMargin: '50px',
      },
    );

    elements.forEach(element => {
      imageObserver.observe(element);
    });
  }

  // 设置预加载
  private setupPreloading() {
    // 预加载关键资源
    const links = document.querySelectorAll('link[rel="preload"]');
    links.forEach(link => {
      const href = link.getAttribute('href');
      if (href && !this.isResourceCached(href)) {
        const fetchLink = document.createElement('link');
        fetchLink.rel = 'prefetch';
        fetchLink.href = href;
        document.head.appendChild(fetchLink);
      }
    });
  }

  // 设置缓存
  private setupCaching() {
    // 注册Service Worker
    if ('serviceWorker' in navigator && this.config.optimization.cache) {
      navigator.serviceWorker
        .register('/sw.js')
        .then(registration => {
          if (DEV) {
            console.log('Service Worker registered:', registration);
          }
        })
        .catch(error => {
          if (DEV) {
            console.warn('Service Worker registration failed:', error);
          }
        });
    }
  }

  // 检查资源是否已缓存
  private isResourceCached(url: string): boolean {
    void url;
    return false;
  }

  // 刷新缓冲区
  private maybeFlushBuffer() {
    if (this.metricBuffer.length >= this.config.reporting.batchSize) {
      this.flushBuffer();
    }
  }

  // 刷新缓冲区
  private flushBuffer() {
    if (this.metricBuffer.length === 0) return;

    const metrics = [...this.metricBuffer];
    this.metricBuffer = [];

    if (this.config.reporting.enabled && this.config.reporting.endpoint) {
      this.sendMetrics(metrics);
    }
  }

  // 发送指标
  private async sendMetrics(metrics: PerformanceMetrics[]) {
    try {
      await fetch(this.config.reporting.endpoint!, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          metrics,
          timestamp: Date.now(),
          userAgent: navigator.userAgent,
          url: window.location.href,
        }),
        keepalive: true,
      });
    } catch (error) {
      if (DEV) {
        console.warn('Failed to send performance metrics:', error);
      }
    }
  }

  // 获取当前指标
  getCurrentMetrics(): PerformanceMetrics | null {
    return this.metrics ? { ...this.metrics } : null;
  }

  // 获取性能评分
  getPerformanceScore(): number {
    if (!this.metrics) return 0;

    const metrics = this.metrics;
    let score = 100;

    // 根据各项指标计算分数
    if (metrics.fcp > PERFORMANCE_THRESHOLDS.FCP) {
      score -= ((metrics.fcp - PERFORMANCE_THRESHOLDS.FCP) / PERFORMANCE_THRESHOLDS.FCP) * 10;
    }
    if (metrics.lcp > PERFORMANCE_THRESHOLDS.LCP) {
      score -= ((metrics.lcp - PERFORMANCE_THRESHOLDS.LCP) / PERFORMANCE_THRESHOLDS.LCP) * 15;
    }
    if (metrics.fid > PERFORMANCE_THRESHOLDS.FID) {
      score -= ((metrics.fid - PERFORMANCE_THRESHOLDS.FID) / PERFORMANCE_THRESHOLDS.FID) * 20;
    }
    if (metrics.cls > PERFORMANCE_THRESHOLDS.CLS) {
      score -= ((metrics.cls - PERFORMANCE_THRESHOLDS.CLS) / PERFORMANCE_THRESHOLDS.CLS) * 25;
    }
    if (metrics.ttfb > PERFORMANCE_THRESHOLDS.TTFB) {
      score -= ((metrics.ttfb - PERFORMANCE_THRESHOLDS.TTFB) / PERFORMANCE_THRESHOLDS.TTFB) * 10;
    }

    return Math.max(0, Math.round(score));
  }

  // 销毁
  destroy() {
    this.observers.forEach(observer => observer.disconnect());
    this.observers = [];
    this.metrics = null;
    this.metricBuffer = [];
    PerformanceService.instance = null as any;
  }
}

import { ref, computed } from 'vue';
import { useAuthStore } from '@/stores/auth';
import { mediaApi } from '@/api';
import type { MediaResource } from '@/types/media';
import type { Recommendation, RecommendationType } from '@/types/history';

export const useRecommendationService = () => {
  const authStore = useAuthStore();
  const isLoading = ref(false);
  const error = ref<string | null>(null);
  const recommendations = ref<Recommendation[]>([]);
  const personalizedMedia = ref<MediaResource[]>([]);

  // 基于用户观看历史生成推荐
  const generatePersonalizedRecommendations = async (limit: number = 10) => {
    if (!authStore.isAuthenticated) {
      return [];
    }

    try {
      isLoading.value = true;
      error.value = null;

      // 获取用户观看历史
      const watchHistory = await mediaApi.getWatchHistory({ limit: 20 });

      // 获取用户收藏
      const favorites = await mediaApi.getFavorites({ limit: 20 });

      // 提取用户偏好的类型和标签
      const userPreferences = analyzeUserPreferences([
        ...watchHistory.data.map(item => item.mediaResource),
        ...favorites.data,
      ]);

      // 基于偏好获取推荐
      const recommendedMedia = await mediaApi.getRecommendedMedia({
        limit,
      });

      personalizedMedia.value = recommendedMedia;
      return recommendedMedia;
    } catch (err) {
      console.error('生成个性化推荐失败:', err);
      error.value = '获取推荐失败';
      return [];
    } finally {
      isLoading.value = false;
    }
  };

  // 分析用户偏好
  const analyzeUserPreferences = (mediaList: any[]) => {
    const typeCount: Record<string, number> = {};
    const genreCount: Record<string, number> = {};
    const ratingSum: Record<string, number> = {};
    const ratingCount: Record<string, number> = {};

    mediaList.forEach(media => {
      // 统计类型偏好
      if (media.type) {
        typeCount[media.type] = (typeCount[media.type] || 0) + 1;
      }

      // 统计类型偏好
      if (media.genres) {
        media.genres.forEach((genre: string) => {
          genreCount[genre] = (genreCount[genre] || 0) + 1;
        });
      }

      // 统计评分偏好
      if (media.rating) {
        const type = media.type;
        ratingSum[type] = (ratingSum[type] || 0) + media.rating;
        ratingCount[type] = (ratingCount[type] || 0) + 1;
      }
    });

    // 找出最偏好的类型
    const preferredTypes = Object.entries(typeCount)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 3)
      .map(([type]) => type);

    // 找出最偏好的类型
    const preferredGenres = Object.entries(genreCount)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5)
      .map(([genre]) => genre);

    // 计算平均评分偏好
    const avgRatingByType: Record<string, number> = {};
    Object.keys(ratingSum).forEach(type => {
      avgRatingByType[type] = ratingSum[type] / ratingCount[type];
    });

    return {
      preferredTypes,
      preferredGenres,
      avgRatingByType,
      totalWatched: mediaList.length,
    };
  };

  // 获取相似推荐
  const getSimilarMedia = async (mediaId: string, limit: number = 8) => {
    try {
      const media = await mediaApi.getMediaById(mediaId);

      // 基于当前媒体的特征获取相似内容
      const similarMedia = await mediaApi.getMediaByType(media.type, {
        limit,
        minRating: Math.max(0, (media.rating || 0) - 1),
        sortBy: 'rating',
        sortOrder: 'DESC',
      });

      return similarMedia.data.filter(m => m.id !== parseInt(mediaId));
    } catch (err) {
      console.error('获取相似媒体失败:', err);
      return [];
    }
  };

  // 获取趋势内容
  const getTrendingMedia = async (limit: number = 10) => {
    try {
      const trending = await mediaApi.getPopularMedia(limit, {
        sortBy: 'viewCount',
        sortOrder: 'DESC',
      });
      return trending;
    } catch (err) {
      console.error('获取趋势内容失败:', err);
      return [];
    }
  };

  // 计算推荐分数
  const calculateRecommendationScore = (
    media: MediaResource,
    userPreferences: ReturnType<typeof analyzeUserPreferences>,
  ) => {
    let score = 0;

    // 类型匹配分数 (40%)
    if (userPreferences.preferredTypes.includes(media.type)) {
      score += 40;
    }

    // 类型匹配分数 (30%)
    if (media.genres) {
      const matchingGenres = media.genres.filter(genre =>
        userPreferences.preferredGenres.includes(genre),
      );
      score += (matchingGenres.length / Math.max(1, userPreferences.preferredGenres.length)) * 30;
    }

    // 评分匹配分数 (20%)
    if (media.rating && userPreferences.avgRatingByType[media.type]) {
      const ratingDiff = Math.abs(media.rating - userPreferences.avgRatingByType[media.type]);
      score += Math.max(0, 20 - ratingDiff * 5);
    }

    // 观看次数分数 (10%)
    if (media.viewCount) {
      score += Math.min(10, Math.log10(media.viewCount + 1));
    }

    return score;
  };

  // 生成推荐理由
  const generateRecommendationReason = (
    media: MediaResource,
    userPreferences: ReturnType<typeof analyzeUserPreferences>,
    type: RecommendationType,
  ) => {
    const reasons = [];

    switch (type) {
      case 'personalized':
        if (userPreferences.preferredTypes.includes(media.type)) {
          reasons.push(`根据您喜欢的${media.type}类型推荐`);
        }
        if (media.genres && media.genres.some(g => userPreferences.preferredGenres.includes(g))) {
          reasons.push(
            `包含您偏好的${media.genres.find(g => userPreferences.preferredGenres.includes(g))}类型`,
          );
        }
        if (media.rating && media.rating >= 8) {
          reasons.push('高评分内容');
        }
        break;

      case 'similar':
        reasons.push('与您观看的内容相似');
        break;

      case 'trending':
        reasons.push('热门推荐');
        break;

      case 'popular':
        reasons.push('受欢迎内容');
        break;
    }

    return reasons.join('，') || '为您推荐';
  };

  // 深度学习推荐算法（简化版）
  const mlRecommendation = async (limit: number = 10) => {
    if (!authStore.isAuthenticated) {
      return [];
    }

    try {
      // 获取用户历史数据
      const userHistory = await mediaApi.getWatchHistory({ limit: 50 });
      const userFavorites = await mediaApi.getFavorites({ limit: 30 });

      // 构建用户画像
      const userProfile = {
        watchedTypes: {} as Record<string, number>,
        watchedGenres: {} as Record<string, number>,
        avgWatchTime: 0,
        completionRate: 0,
        ratingTrend: 'stable' as 'increasing' | 'stable' | 'decreasing',
      };

      // 分析用户画像
      userHistory.data.forEach((item: any) => {
        if (item.mediaResource?.type) {
          userProfile.watchedTypes[item.mediaResource.type] =
            (userProfile.watchedTypes[item.mediaResource.type] || 0) + 1;
        }
        if (item.mediaResource?.genres) {
          item.mediaResource.genres.forEach((genre: string) => {
            userProfile.watchedGenres[genre] = (userProfile.watchedGenres[genre] || 0) + 1;
          });
        }

        // 计算观看完成度
        if (item.duration && item.currentTime) {
          userProfile.completionRate += item.currentTime / item.duration;
        }
      });

      userProfile.completionRate /= Math.max(1, userHistory.data.length);
      userProfile.avgWatchTime =
        userHistory.data.reduce((sum: number, item: any) => sum + (item.currentTime || 0), 0) /
        Math.max(1, userHistory.data.length);

      // 获取候选媒体
      const candidateMedia = await mediaApi.getMediaList({ limit: 100 });

      // 计算推荐分数
      const scoredMedia = candidateMedia.data.map(media => {
        const score = calculateMLScore(media, userProfile);
        return { ...media, score };
      });

      // 返回最高分的媒体
      return scoredMedia
        .sort((a, b) => b.score - a.score)
        .slice(0, limit)
        .map(({ score, ...media }) => media);
    } catch (err) {
      console.error('ML推荐失败:', err);
      return [];
    }
  };

  // ML分数计算
  const calculateMLScore = (media: MediaResource, userProfile: any) => {
    let score = 0;

    // 类型权重 (30%)
    const typeScore = userProfile.watchedTypes[media.type] || 0;
    score +=
      (typeScore /
        Math.max(
          1,
          (Object.values(userProfile.watchedTypes) as number[]).reduce((a, b) => a + b, 0),
        )) *
      30;

    // 类型权重 (25%)
    if (media.genres) {
      const genreScore = media.genres.reduce(
        (sum, genre) => sum + (userProfile.watchedGenres[genre] || 0),
        0,
      );
      const totalGenreViews = (Object.values(userProfile.watchedGenres) as number[]).reduce(
        (a, b) => a + b,
        0,
      );
      score += (genreScore / Math.max(1, totalGenreViews)) * 25;
    }

    // 评分权重 (20%)
    if (media.rating) {
      score += Math.min(20, media.rating * 2);
    }

    // 观看完成度匹配 (15%)
    if (userProfile.completionRate > 0.7 && media.duration) {
      // 为观看完成度高的用户推荐较长内容
      score += media.duration > 120 ? 15 : 5;
    } else if (userProfile.completionRate < 0.3 && media.duration) {
      // 为观看完成度低的用户推荐较短内容
      score += media.duration < 60 ? 15 : 5;
    }

    // 新鲜度权重 (10%)
    const daysSinceCreated =
      (Date.now() - new Date(media.createdAt).getTime()) / (1000 * 60 * 60 * 24);
    if (daysSinceCreated < 30) {
      score += 10;
    } else if (daysSinceCreated < 90) {
      score += 5;
    }

    return score;
  };

  return {
    // 状态
    isLoading: computed(() => isLoading.value),
    error: computed(() => error.value),
    recommendations: computed(() => recommendations.value),
    personalizedMedia: computed(() => personalizedMedia.value),

    // 方法
    generatePersonalizedRecommendations,
    getSimilarMedia,
    getTrendingMedia,
    mlRecommendation,
    analyzeUserPreferences,
    calculateRecommendationScore,
    generateRecommendationReason,

    // 计算属性
    isAuthenticated: computed(() => authStore.isAuthenticated),
    hasRecommendations: computed(() => recommendations.value.length > 0),
  };
};

/**
 * 资源缓存管理器
 */

// 缓存配置
export interface CacheConfig {
  name: string;
  maxSize: number; // 最大缓存条目数
  ttl: number; // 生存时间（毫秒）
  storageType: 'memory' | 'local' | 'session'; // 存储类型
  compression?: boolean; // 是否压缩数据
  cleanupInterval?: number; // 清理间隔（毫秒）
}

// 缓存条目
export interface CacheEntry<T> {
  key: string;
  value: T;
  timestamp: number;
  ttl: number;
  accessCount: number;
  lastAccess: number;
  size: number;
}

// 缓存统计
export interface CacheStats {
  hits: number;
  misses: number;
  evictions: number;
  size: number;
  maxSize: number;
  hitRate: number;
  entries: number;
  memoryUsage: number;
}

export class ResourceCache<T = any> {
  private config: CacheConfig;
  private cache: Map<string, CacheEntry<T>>;
  private stats: CacheStats;
  private cleanupTimer?: ReturnType<typeof setInterval>;
  private changeListeners: Map<string, (key: string, value: T | null) => void> = new Map();

  constructor(config: CacheConfig) {
    this.config = {
      cleanupInterval: 60000, // 默认1分钟清理一次
      compression: false,
      ...config,
    };

    this.cache = new Map();
    this.stats = {
      hits: 0,
      misses: 0,
      evictions: 0,
      size: 0,
      maxSize: this.config.maxSize,
      hitRate: 0,
      entries: 0,
      memoryUsage: 0,
    };

    this.loadFromStorage();
    this.startCleanup();
  }

  // 设置缓存
  set(key: string, value: T, ttl?: number): void {
    const size = this.calculateSize(value);

    // 如果缓存已满，清理空间
    if (this.cache.size >= this.config.maxSize) {
      this.evict();
    }

    const entry: CacheEntry<T> = {
      key,
      value,
      timestamp: Date.now(),
      ttl: ttl || this.config.ttl,
      accessCount: 0,
      lastAccess: Date.now(),
      size,
    };

    this.cache.set(key, entry);
    this.updateStats('set', size);
    this.saveToStorage();
    this.notifyChange(key, value);
  }

  // 获取缓存
  get(key: string): T | null {
    const entry = this.cache.get(key);

    if (!entry) {
      this.updateStats('miss');
      return null;
    }

    // 检查是否过期
    if (this.isExpired(entry)) {
      this.delete(key);
      this.updateStats('miss');
      return null;
    }

    // 更新访问信息
    entry.accessCount++;
    entry.lastAccess = Date.now();

    this.updateStats('hit');
    this.notifyChange(key, entry.value);

    return entry.value;
  }

  // 检查缓存是否存在
  has(key: string): boolean {
    const entry = this.cache.get(key);
    if (!entry) return false;

    if (this.isExpired(entry)) {
      this.delete(key);
      return false;
    }

    return true;
  }

  // 删除缓存
  delete(key: string): boolean {
    const deleted = this.cache.delete(key);
    if (deleted) {
      this.updateStats('delete');
      this.saveToStorage();
      this.notifyChange(key, null);
    }
    return deleted;
  }

  // 清空缓存
  clear(): void {
    this.cache.forEach((entry, key) => {
      this.notifyChange(key, null);
    });
    this.cache.clear();
    this.stats.entries = 0;
    this.stats.size = 0;
    this.stats.memoryUsage = 0;
    this.saveToStorage();
  }

  // 获取所有键
  keys(): string[] {
    return Array.from(this.cache.keys());
  }

  // 获取所有值
  values(): T[] {
    return Array.from(this.cache.values()).map(entry => entry.value);
  }

  // 获取所有条目
  entries(): Array<{ key: string; value: T }> {
    return Array.from(this.cache.entries()).map(([key, entry]) => ({
      key,
      value: entry.value,
    }));
  }

  // 获取缓存大小
  size(): number {
    return this.cache.size;
  }

  // 获取缓存统计信息
  getStats(): CacheStats {
    return { ...this.stats };
  }

  // 批量获取
  batchGet(keys: string[]): (T | null)[] {
    return keys.map(key => this.get(key));
  }

  // 批量设置
  batchSet(entries: Array<{ key: string; value: T; ttl?: number }>): void {
    entries.forEach(({ key, value, ttl }) => {
      this.set(key, value, ttl);
    });
  }

  // 模糊匹配获取
  getFuzzy(pattern: string, limit = 5): Array<{ key: string; value: T }> {
    const results: Array<{ key: string; value: T; score: number }> = [];

    this.cache.forEach((entry, key) => {
      const score = this.calculateFuzzyScore(key, pattern);
      if (score > 0.5) {
        // 0.5 是模糊匹配的阈值
        results.push({ key, value: entry.value, score });
      }
    });

    return results
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(({ key, value }) => ({ key, value }));
  }

  // 添加变化监听器
  onChange(key: string, callback: (key: string, value: T | null) => void): void {
    this.changeListeners.set(key, callback);
  }

  // 移除变化监听器
  offChange(key: string): void {
    this.changeListeners.delete(key);
  }

  // 清理过期缓存
  cleanup(): number {
    let count = 0;
    const now = Date.now();

    this.cache.forEach((entry, key) => {
      if (this.isExpired(entry)) {
        this.delete(key);
        count++;
      }
    });

    return count;
  }

  // 清理最久未使用的缓存
  cleanupLRU(count = Math.ceil(this.config.maxSize * 0.2)): number {
    const entries = Array.from(this.cache.entries())
      .map(([key, entry]) => ({ key, entry }))
      .sort((a, b) => a.entry.lastAccess - b.entry.lastAccess);

    let deletedCount = 0;
    for (let i = 0; i < Math.min(count, entries.length); i++) {
      const { key } = entries[i];
      if (this.delete(key)) {
        deletedCount++;
      }
    }

    return deletedCount;
  }

  // 清理最少使用的缓存
  cleanupLFU(count = Math.ceil(this.config.maxSize * 0.2)): number {
    const entries = Array.from(this.cache.entries())
      .map(([key, entry]) => ({ key, entry }))
      .sort((a, b) => a.entry.accessCount - b.entry.accessCount);

    let deletedCount = 0;
    for (let i = 0; i < Math.min(count, entries.length); i++) {
      const { key } = entries[i];
      if (this.delete(key)) {
        deletedCount++;
      }
    }

    return deletedCount;
  }

  // 序列化缓存到存储
  private saveToStorage(): void {
    if (this.config.storageType === 'memory') return;

    try {
      const data = {
        cache: Array.from(this.cache.entries()),
        stats: this.stats,
        timestamp: Date.now(),
      };

      const serialized = JSON.stringify(data);

      // 压缩数据
      if (this.config.compression) {
        // 这里可以添加压缩逻辑
        // serialized = compress(serialized)
      }

      if (this.config.storageType === 'local') {
        localStorage.setItem(`cache_${this.config.name}`, serialized);
      } else if (this.config.storageType === 'session') {
        sessionStorage.setItem(`cache_${this.config.name}`, serialized);
      }
    } catch (error) {
      console.warn(`Failed to save cache ${this.config.name} to storage:`, error);
    }
  }

  // 从存储加载缓存
  private loadFromStorage(): void {
    if (this.config.storageType === 'memory') return;

    try {
      let serialized: string | null = null;

      if (this.config.storageType === 'local') {
        serialized = localStorage.getItem(`cache_${this.config.name}`);
      } else if (this.config.storageType === 'session') {
        serialized = sessionStorage.getItem(`cache_${this.config.name}`);
      }

      if (!serialized) return;

      // 解压缩数据
      if (this.config.compression) {
        // 这里可以添加解压缩逻辑
        // serialized = decompress(serialized)
      }

      const data = JSON.parse(serialized);

      // 重构缓存
      this.cache = new Map(data.cache || []);

      // 更新统计
      if (data.stats) {
        this.stats = { ...data.stats, maxSize: this.config.maxSize };
      }

      // 清理过期条目
      this.cleanup();
    } catch (error) {
      console.warn(`Failed to load cache ${this.config.name} from storage:`, error);
    }
  }

  // 开始自动清理
  private startCleanup(): void {
    if (this.config.cleanupInterval && this.config.cleanupInterval > 0) {
      this.cleanupTimer = setInterval(() => {
        this.cleanup();
      }, this.config.cleanupInterval);
    }
  }

  // 停止自动清理
  private stopCleanup(): void {
    if (this.cleanupTimer) {
      clearInterval(this.cleanupTimer);
      this.cleanupTimer = undefined;
    }
  }

  // 淘汰缓存
  private evict(): void {
    // 优先清理过期的
    if (this.cleanup() > 0) {
      return;
    }

    // 使用LRU策略
    this.cleanupLRU(1);

    this.stats.evictions++;
  }

  // 检查缓存是否过期
  private isExpired(entry: CacheEntry<T>): boolean {
    return Date.now() - entry.timestamp > entry.ttl;
  }

  // 计算数据大小
  private calculateSize(value: T): number {
    try {
      return JSON.stringify(value).length * 2; // 简单估算，2字节每字符
    } catch {
      return 1024; // 默认1KB
    }
  }

  // 计算模糊匹配分数
  private calculateFuzzyScore(key: string, pattern: string): number {
    if (!key || !pattern) return 0;

    // 简单的包含匹配
    if (key.includes(pattern)) return 1.0;

    // 模糊匹配逻辑
    const patternLower = pattern.toLowerCase();
    const keyLower = key.toLowerCase();

    if (patternLower === keyLower) return 1.0;

    // 部分匹配
    let score = 0;
    let patternIndex = 0;
    let keyIndex = 0;

    while (patternIndex < patternLower.length && keyIndex < keyLower.length) {
      if (patternLower[patternIndex] === keyLower[keyIndex]) {
        score++;
        patternIndex++;
      } else {
        score *= 0.9;
        keyIndex++;
      }
    }

    return score / Math.max(patternLower.length, keyLower.length);
  }

  // 更新统计信息
  private updateStats(action: 'hit' | 'miss' | 'set' | 'delete', size = 0): void {
    switch (action) {
      case 'hit':
        this.stats.hits++;
        break;
      case 'miss':
        this.stats.misses++;
        break;
      case 'set':
        this.stats.entries = this.cache.size;
        this.stats.size += size;
        break;
      case 'delete':
        this.stats.entries = this.cache.size;
        this.stats.size = Math.max(0, this.stats.size - size);
        break;
    }

    // 计算命中率
    const total = this.stats.hits + this.stats.misses;
    this.stats.hitRate = total > 0 ? this.stats.hits / total : 0;

    // 估算内存使用
    this.stats.memoryUsage = this.stats.size;
  }

  // 通知变化
  private notifyChange(key: string, value: T | null): void {
    const callback = this.changeListeners.get(key);
    if (callback) {
      try {
        callback(key, value);
      } catch (error) {
        console.error(`Cache change listener error for key ${key}:`, error);
      }
    }
  }

  // 销毁缓存
  destroy(): void {
    this.stopCleanup();
    this.clear();
    this.changeListeners.clear();
  }
}

// 创建预配置的缓存实例
export const createCache = <T = any>(config: CacheConfig) => new ResourceCache<T>(config);

// 默认配置
export const DEFAULT_CACHE_CONFIG = {
  maxSize: 100,
  ttl: 300000, // 5分钟
  storageType: 'memory',
  compression: false,
  cleanupInterval: 60000,
} satisfies Omit<CacheConfig, 'name'>;

// 创建默认缓存
export const createDefaultCache = <T = any>(name: string, overrides?: Partial<CacheConfig>) => {
  return createCache<T>({
    name,
    ...DEFAULT_CACHE_CONFIG,
    ...overrides,
  } as CacheConfig);
};

// 全局缓存实例
export const globalCache = createDefaultCache('global', {
  maxSize: 500,
  ttl: 1800000, // 30分钟
});

// API缓存实例
export const apiCache = createDefaultCache('api', {
  maxSize: 1000,
  ttl: 300000, // 5分钟
  storageType: 'session',
});

// 图片缓存实例
export const imageCache = createDefaultCache('images', {
  maxSize: 200,
  ttl: 3600000, // 1小时
  storageType: 'local',
  compression: true,
});

// 组件缓存实例
export const componentCache = createDefaultCache('components', {
  maxSize: 50,
  ttl: 600000, // 10分钟
  storageType: 'memory',
});

// 导出缓存工具函数
export const cacheUtils = {
  // 创建缓存键
  createKey: (namespace: string, ...parts: string[]): string => {
    return `${namespace}:${parts.join(':')}`;
  },

  // 创建带有版本控制的缓存键
  createVersionedKey: (namespace: string, version: string, ...parts: string[]): string => {
    return `${namespace}:${version}:${parts.join(':')}`;
  },

  // 创建带有时间戳的缓存键
  createTimestampKey: (namespace: string, timestamp: number, ...parts: string[]): string => {
    return `${namespace}:${timestamp}:${parts.join(':')}`;
  },

  // 计算缓存大小
  calculateCacheSize: (cache: ResourceCache): number => {
    const stats = cache.getStats();
    return stats.size;
  },

  // 清理所有缓存
  clearAllCaches: () => {
    globalCache.clear();
    apiCache.clear();
    imageCache.clear();
    componentCache.clear();
  },

  // 获取所有缓存的统计信息
  getAllCacheStats: () => ({
    global: globalCache.getStats(),
    api: apiCache.getStats(),
    images: imageCache.getStats(),
    components: componentCache.getStats(),
  }),

  // 优化缓存配置
  optimizeConfig: (
    config: CacheConfig,
    memoryInfo?: { used: number; total: number },
  ): CacheConfig => {
    if (!memoryInfo) return config;

    const memoryUsagePercent = memoryInfo.used / memoryInfo.total;

    // 如果内存使用超过80%，减少缓存大小
    if (memoryUsagePercent > 0.8) {
      config.maxSize = Math.floor(config.maxSize * 0.7);
      config.cleanupInterval = Math.max(10000, config.cleanupInterval * 0.8);
    }
    // 如果内存使用小于50%，可以增加缓存大小
    else if (memoryUsagePercent < 0.5) {
      config.maxSize = Math.floor(config.maxSize * 1.2);
    }

    return config;
  },
};

import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { authApi } from '@/api/auth';
import type { User } from '@/types/user';

export const useAuthStore = defineStore('auth', () => {
  const user = ref<User | null>(null);
  const token = ref(localStorage.getItem('token') || '');
  const isLoading = ref(false);

  const isAuthenticated = computed(() => !!token.value);

  const login = async (credentials: { identifier: string; password: string }) => {
    isLoading.value = true;
    try {
      const response = await authApi.login(credentials);
      const { accessToken, user: userData } = response;

      token.value = accessToken;
      user.value = userData;
      localStorage.setItem('token', accessToken);

      return { success: true };
    } catch (error: any) {
      return {
        success: false,
        error: error?.message || '登录失败',
      };
    } finally {
      isLoading.value = false;
    }
  };

  const register = async (userData: {
    username: string;
    email: string;
    password: string;
    phone?: string;
    nickname?: string;
  }) => {
    isLoading.value = true;
    try {
      const response = await authApi.register(userData);
      return { success: true, data: response };
    } catch (error: any) {
      return {
        success: false,
        error: error?.message || '注册失败',
      };
    } finally {
      isLoading.value = false;
    }
  };

  const logout = () => {
    token.value = '';
    user.value = null;
    localStorage.removeItem('token');
  };

  const fetchUserProfile = async (): Promise<void> => {
    if (!token.value) return;

    try {
      const response = await authApi.getProfile();
      user.value = response;
    } catch (error) {
      console.error('获取用户信息失败:', error);
      logout();
    }
  };

  return {
    user,
    token,
    isLoading,
    isAuthenticated,
    login,
    register,
    logout,
    fetchUserProfile,
  };
});

import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { mediaApi } from '@/api/media';
import type { PaginatedResponse, PaginationParams, FilterParams } from '@/types/api';
import type { MediaResource, MediaQueryParams } from '@/types/media';

// 定义分页类型
interface Pagination {
  page: number;
  limit: number;
  total: number;
  totalPages: number;
}

export const useMediaStore = defineStore('media', () => {
  const mediaList = ref<MediaResource[]>([]);
  const currentMedia = ref<MediaResource | null>(null);
  const loading = ref(false);
  const pagination = ref<Pagination>({
    page: 1,
    limit: 10,
    total: 0,
    totalPages: 0,
  });

  const hasMore = computed(() => {
    return pagination.value.page < pagination.value.totalPages;
  });

  const fetchMediaList = async (params: MediaQueryParams = {}) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaList(params);
      mediaList.value = response.data;
      pagination.value = {
        page: params.page || 1,
        limit: params.limit || 10,
        total: response.total || 0,
        totalPages: Math.ceil((response.total || 0) / (params.limit || 10)),
      };
      return response;
    } catch (error) {
      console.error('获取媒体列表失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchMediaDetail = async (id: string | number) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaById(String(id));
      currentMedia.value = response;
      return response;
    } catch (error) {
      console.error('获取媒体详情失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchPopularMedia = async (limit = 10, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getPopularMedia(limit, params);
      return response;
    } catch (error) {
      console.error('获取热门媒体失败:', error);
      throw error;
    }
  };

  const fetchLatestMedia = async (limit = 10, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getLatestMedia(limit, params);
      return response;
    } catch (error) {
      console.error('获取最新媒体失败:', error);
      throw error;
    }
  };

  const fetchTopRatedMedia = async (limit = 10, minRating = 8, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getTopRatedMedia(limit, minRating, params);
      return response;
    } catch (error) {
      console.error('获取高评分媒体失败:', error);
      throw error;
    }
  };

  const fetchRecommendations = async (mediaId: string | number, limit = 6) => {
    try {
      return await mediaApi.getSimilarMedia(mediaId, limit);
    } catch (error) {
      console.error('获取推荐媒体失败:', error);
      throw error;
    }
  };

  const searchMedia = async (query: string, params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.searchMedia(query, params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('搜索媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchMediaByType = async (type: string, params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaByType(type, params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('获取类型媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const incrementViewCount = async (id: string) => {
    try {
      await mediaApi.incrementViewCount(id);
    } catch (error) {
      console.error('增加观看次数失败:', error);
    }
  };

  const toggleFavorite = async (id: string, currentState?: boolean) => {
    try {
      const response = await mediaApi.toggleFavorite(id, currentState);
      // 清除相关缓存
      mediaApi.clearCache();
      return response.isFavorited;
    } catch (error) {
      console.error('切换收藏状态失败:', error);
      throw error;
    }
  };

  const fetchFavoriteStatus = async (id: string) => {
    try {
      const response = await mediaApi.getFavoriteStatus(id);
      return response.isFavorited;
    } catch (error) {
      console.error('获取收藏状态失败:', error);
      throw error;
    }
  };

  const fetchFavorites = async (params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.getFavorites(params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('获取收藏媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const clearCurrentMedia = () => {
    currentMedia.value = null;
  };

  const resetMediaList = () => {
    mediaList.value = [];
    pagination.value = {
      page: 1,
      limit: 10,
      total: 0,
      totalPages: 0,
    };
  };

  const loadMore = async (params?: MediaQueryParams) => {
    if (!hasMore.value || loading.value) return;

    loading.value = true;
    try {
      const nextPage = pagination.value.page + 1;
      const response = await mediaApi.getMediaList({
        ...params,
        page: nextPage,
        limit: pagination.value.limit,
      });

      mediaList.value = [...mediaList.value, ...response.data];
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('加载更多媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  return {
    mediaList,
    currentMedia,
    loading,
    pagination,
