import axios, { type AxiosInstance } from 'axios';
import type { AxiosRequestConfig, AxiosResponse } from 'axios';

interface CacheConfig {
  ttl?: number; // 默认5分钟
  key?: string; // 自定义缓存key
  forceRefresh?: boolean; // 强制刷新
  enabled?: boolean; // 是否启用缓存，默认true
}

// 扩展 AxiosRequestConfig 以包含缓存配置
interface CachedAxiosRequestConfig extends AxiosRequestConfig {
  cacheConfig?: CacheConfig;
}

interface CacheItem<T = any> {
  data: T;
  timestamp: number;
  ttl: number;
  key: string;
}

/**
 * API缓存工具类
 */
class APICacheManager {
  private cache = new Map<string, CacheItem>();
  private maxSize = 1000; // 最大缓存条目数
  private cleanupInterval: number | null = null;

  constructor() {
    // 定期清理过期缓存
    this.startCleanup();
  }

  /**
   * 生成缓存key
   */
  private generateKey(config: CachedAxiosRequestConfig): string {
    const { url, method, params, data } = config;
    const normalizedUrl = (url || '').replace(/\/$/, ''); // 移除尾部斜杠

    // 基于URL、方法、参数和数据生成唯一key
    const keyObj = {
      url: normalizedUrl,
      method: method?.toLowerCase() || 'get',
      params: params ? JSON.stringify(params) : '',
      data: data ? JSON.stringify(data) : '',
    };

    return btoa(JSON.stringify(keyObj));
  }

  /**
   * 检查缓存是否有效
   */
  private isCacheValid(item: CacheItem): boolean {
    const now = Date.now();
    return now - item.timestamp < item.ttl;
  }

  /**
   * 获取缓存数据
   */
  private getCache<T = any>(key: string): T | null {
    const item = this.cache.get(key);
    if (!item || !this.isCacheValid(item)) {
      return null;
    }
    return item.data;
  }

  /**
   * 设置缓存数据
   */
  private setCache<T = any>(key: string, data: T, ttl: number): void {
    // 清理过期的缓存
    this.cleanupExpired();

    // 如果缓存已满，删除最旧的条目
    if (this.cache.size >= this.maxSize) {
      const oldestKey = this.cache.keys().next().value;
      if (oldestKey) {
        this.cache.delete(oldestKey);
      }
    }

    this.cache.set(key, {
      data,
      timestamp: Date.now(),
      ttl,
      key,
    });
  }

  /**
   * 清理过期缓存
   */
  private cleanupExpired(): void {
    const now = Date.now();
    const keysToDelete: string[] = [];

    this.cache.forEach((item, key) => {
      if (now - item.timestamp >= item.ttl) {
        keysToDelete.push(key);
      }
    });

    keysToDelete.forEach(key => this.cache.delete(key));
  }

  /**
   * 启动定期清理
   */
  private startCleanup(): void {
    this.cleanupInterval = setInterval(() => {
      this.cleanupExpired();
    }, 60000); // 每分钟清理一次
  }

  /**
   * 中断请求处理
   */
  private async handleRequest<T = any>(
    config: AxiosRequestConfig,
    cacheKey: string,
    cacheConfig: CacheConfig,
  ): Promise<AxiosResponse<T>> {
    try {
      const response = await axios(config);

      // 缓存成功的响应
      if (response.status >= 200 && response.status < 300) {
        const ttl = cacheConfig.ttl || 300000; // 默认5分钟
        this.setCache(cacheKey, response.data, ttl);
      }

      return response;
    } catch (error) {
      // 对于某些错误，可以返回缓存的旧数据
      if (error.response?.status === 503 || error.response?.status === 504) {
        const cachedData = this.getCache(cacheKey);
        if (cachedData) {
          // 返回缓存的旧数据，并标记为过期数据
          return {
            ...error.response,
            data: cachedData,
            status: 200,
            cached: true,
            cachedAt: this.cache.get(cacheKey)?.timestamp,
          };
        }
      }

      throw error;
    }
  }

  /**
   * 请求拦截器
   */
  public async requestInterceptor(
    config: CachedAxiosRequestConfig,
  ): Promise<CachedAxiosRequestConfig> {
    // 只缓存GET请求，除非显式配置
    if (config.method?.toLowerCase() !== 'get' && !config.cacheConfig?.enabled) {
      return config;
    }

    const cacheConfig = config.cacheConfig || {};
    if (cacheConfig.enabled === false) {
      return config;
    }

    if (cacheConfig.forceRefresh) {
      return config;
    }

    const key = cacheConfig.key || this.generateKey(config);
    const cachedData = this.getCache(key);

    if (cachedData) {
      // 如果有缓存数据，直接返回，不发送网络请求
      throw Object.assign(new Error('Cache hit'), {
        __cacheHit: true,
        config,
      });
    }

    return config;
  }

  /**
   * 响应拦截器
   */
  public async responseInterceptor(error: any): Promise<any> {
    if (!error?.__cacheHit) {
      throw error;
    }

    // 如果是缓存命中，构造响应对象
    const config = error.config as CachedAxiosRequestConfig;
    const cacheConfig = config.cacheConfig || {};
    const key = cacheConfig.key || this.generateKey(config);
    const cachedData = this.getCache(key);

    if (cachedData) {
      return {
        data: cachedData,
        status: 200,
        statusText: 'OK',
        headers: {},
        config,
        cached: true,
        cachedAt: this.cache.get(key)?.timestamp,
      };
    }

    throw error;
  }

  /**
   * 清理指定key的缓存
   */
  public clearCache(key?: string): void {
    if (key) {
      this.cache.delete(key);
    } else {
      this.cache.clear();
    }
  }

  /**
   * 清理指定URL模式的缓存
   */
  public clearCacheByPattern(pattern: string | RegExp): void {
    const keysToDelete: string[] = [];

    this.cache.forEach((item, key) => {
      if (typeof pattern === 'string') {
        if (key.includes(pattern)) {
          keysToDelete.push(key);
        }
      } else if (pattern instanceof RegExp) {
        if (pattern.test(key)) {
          keysToDelete.push(key);
        }
      }
    });

    keysToDelete.forEach(key => this.cache.delete(key));
  }

  /**
   * 获取缓存统计
   */
  public getStats(): Object {
    const now = Date.now();
    let validCount = 0;
    let expiredCount = 0;
    let totalSize = 0;

    this.cache.forEach((item, key) => {
      totalSize += JSON.stringify(item).length;
      if (this.isCacheValid(item)) {
        validCount++;
      } else {
        expiredCount++;
      }
    });

    return {
      total: this.cache.size,
      valid: validCount,
      expired: expiredCount,
      hitRate: validCount / (this.cache.size || 1),
      size: totalSize,
    };
  }

  /**
   * 预加载缓存
   */
  public async preload(urls: string[], ttl: number = 300000): Promise<void> {
    const preloadPromises = urls.map(url => {
      return axios
        .get(url, { cacheConfig: { ttl } } as any)
        .then(() => undefined)
        .catch(() => undefined);
    });

    await Promise.allSettled(preloadPromises);
  }

  /**
   * 销毁清理
   */
  public destroy(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }
    this.cache.clear();
  }
}

// 创建全局缓存管理器实例
export const apiCacheManager = new APICacheManager();

/**
 * 为axios实例添加缓存拦截器
 */
export const setupCacheInterceptors = (instance: AxiosInstance): void => {
  // 请求拦截器
  instance.interceptors.request.use(
    async (config: any) => {
      try {
        return await apiCacheManager.requestInterceptor(config);
      } catch (error) {
        if ((error as any)?.__cacheHit) {
          return Promise.reject(error);
        }
        return config;
      }
    },
    error => Promise.reject(error),
  );

  // 响应拦截器
  instance.interceptors.response.use(
    response => response,
    async error => {
      try {
        return await apiCacheManager.responseInterceptor(error);
      } catch (responseError) {
        return Promise.reject(responseError);
      }
    },
  );
};

/**
 * 缓存配置工具函数
 */
export const withCache = (
  config: CachedAxiosRequestConfig,
  cacheConfig?: CacheConfig,
): CachedAxiosRequestConfig => {
  return {
    ...config,
    cacheConfig: {
      ttl: 300000, // 默认5分钟
      enabled: true,
      ...cacheConfig,
    },
  };
};

/**
 * 强制刷新缓存
 */
export const forceRefresh = (
  config: CachedAxiosRequestConfig,
  cacheConfig?: Omit<CacheConfig, 'forceRefresh'>,
): CachedAxiosRequestConfig => {
  return withCache(config, {
    ...cacheConfig,
    forceRefresh: true,
  });
};

export default apiCacheManager;

import type { AxiosResponse, AxiosError } from 'axios';
import type { ApiResponse } from '@/types/api';

// 重新定义 ApiError 接口以兼容使用方式
interface ApiError {
  message: string;
  status?: number;
  code?: string;
  details?: any;
  data?: any;
}

// 成功响应包装器
export class ApiResponseWrapper {
  static success<T>(data: T, message?: string): ApiResponse<T> {
    return {
      success: true,
      data,
      message,
    };
  }

  static error(message: string, status?: number, data?: any): ApiError {
    return {
      message,
      status: status || 500,
      data: data || {},
    };
  }
}

// API 错误处理器
export class ApiErrorHandler {
  static handle(error: AxiosError): Promise<never> {
    const responseData = error.response?.data as { message?: string } | undefined;

    const apiError: ApiError = {
      message: responseData?.message || error.message || '请求失败',
      status: error.response?.status || 500,
      data: error.response?.data || {},
    };

    // 处理特定错误状态码
    if (error.response && error.response.status === 401) {
      // 调试信息
      if (process.env.NODE_ENV === 'development') {
        console.warn('Authentication failed, clearing token and redirecting to login');
      }
      
      // 未授权，清除本地存储并重定向到登录页
      localStorage.removeItem('token');
      
      // 使用更友好的方式重定向，避免直接 location.href
      if (typeof window !== 'undefined' && !window.location.pathname.includes('/login')) {
        window.location.href = '/login';
      }
    }

    if (error.response && error.response.status === 403) {
      // 禁止访问
      apiError.message = '权限不足，无法访问该资源';
    }

    if (error.response?.status === 404) {
      // 资源不存在
      apiError.message = '请求的资源不存在';
    }

    if (error.response?.status === 429) {
      // 请求过于频繁
      apiError.message = '请求过于频繁，请稍后再试';
    }

    if (error.response?.status >= 500) {
      // 服务器错误
      apiError.message = '服务器内部错误，请稍后再试';
    }

    return Promise.reject(apiError);
  }
}

// 请求拦截器配置
export class RequestInterceptor {
  static config() {
    return {
      onRequest: (config: any) => {
        const token = localStorage.getItem('token');
        if (token) {
          config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
      },
      onResponse: (response: AxiosResponse) => {
        // 保留原始响应对象，避免在 ApiClient 中重复解包后得到 undefined
        return response;
      },
      onResponseError: (error: AxiosError) => {
        const responseData = error.response?.data as { message?: string } | undefined;

        // 调试信息，生产环境可删除
        if (process.env.NODE_ENV === 'development') {
          console.error('API Error:', {
            url: error.config?.url,
            method: error.config?.method,
            status: error.response?.status,
            message: responseData?.message,
            headers: error.config?.headers,
          });
        }
        return ApiErrorHandler.handle(error);
      },
    };
  }
}

// 分页数据处理工具
export class PaginationHelper {
  static processPaginationData<T>(response: any): {
    data: T[];
    pagination: {
      page: number;
      limit: number;
      total: number;
      totalPages: number;
    };
  } {
    return {
      data: response.data || [],
      pagination: {
        page: response.page || 1,
        limit: response.limit || 10,
        total: response.total || 0,
        totalPages: response.totalPages || 0,
      },
    };
  }

  static buildQueryParams(params: {
    page?: number;
    limit?: number;
    sortBy?: string;
    sortOrder?: 'ASC' | 'DESC';
    [key: string]: unknown;
  }): Record<string, any> {
    const query: Record<string, any> = {};

    if (params.page) query.page = params.page;
    if (params.limit) query.limit = params.limit;
    if (params.sortBy) query.sortBy = params.sortBy;
    if (params.sortOrder) query.sortOrder = params.sortOrder;

    // 添加其他查询参数
    Object.keys(params).forEach(key => {
      if (!['page', 'limit', 'sortBy', 'sortOrder'].includes(key) && params[key] !== undefined) {
        query[key] = params[key];
      }
    });

    return query;
  }
}

// 缓存管理工具
export class CacheManager {
  private static cache = new Map<string, { data: any; expires: number }>();
  private static defaultTTL = 5 * 60 * 1000; // 5分钟

  static set(key: string, data: any, ttl: number = this.defaultTTL): void {
    const expires = Date.now() + ttl;
    this.cache.set(key, { data, expires });
  }

  static get<T>(key: string): T | null {
    const item = this.cache.get(key);
    if (!item) return null;

    if (Date.now() > item.expires) {
      this.cache.delete(key);
      return null;
    }

    return item.data;
  }

  static clear(): void {
    this.cache.clear();
  }

  static clearPattern(pattern: RegExp): void {
    for (const [key] of this.cache) {
      if (pattern.test(key)) {
        this.cache.delete(key);
      }
    }
  }
}

// 重试机制工具
export class RetryHelper {
  static async retry<T>(
    fn: () => Promise<T>,
    maxAttempts: number = 3,
    delay: number = 1000,
    backoff: number = 2,
  ): Promise<T> {
    let lastError: Error | unknown;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error;

        if (attempt === maxAttempts) {
          throw lastError;
        }

        // 指数退避
        const waitTime = delay * Math.pow(backoff, attempt - 1);
        await new Promise(resolve => setTimeout(resolve, waitTime));
      }
    }
    
    // TypeScript 要求必须有返回值，但实际上永远不会到达这里
    throw lastError;
  }
}

// 数据验证工具
export class ValidationHelper {
  static validateEmail(email: string): boolean {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  static validatePassword(password: string): {
    isValid: boolean;
    errors: string[];
  } {
    const errors: string[] = [];

    if (password.length < 8) {
      errors.push('密码长度至少8位');
    }

    if (!/[A-Z]/.test(password)) {
      errors.push('密码必须包含大写字母');
    }

    if (!/[a-z]/.test(password)) {
      errors.push('密码必须包含小写字母');
    }

    if (!/\d/.test(password)) {
      errors.push('密码必须包含数字');
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  static sanitizeInput(input: string): string {
    return input
      .trim()
      .replace(/[<>]/g, '') // 移除HTML标签字符
      .replace(/javascript:/gi, '') // 移除JavaScript协议
      .replace(/on\w+\s*=/gi, ''); // 移除事件处理器
  }
}

// 本地存储工具
export class StorageHelper {
  static setItem(key: string, value: any, ttl?: number): void {
    const item = {
      value,
      expires: ttl ? Date.now() + ttl : null,
    };

    localStorage.setItem(key, JSON.stringify(item));
  }

  static getItem<T>(key: string): T | null {
    const itemStr = localStorage.getItem(key);
    if (!itemStr) return null;

    try {
      const item = JSON.parse(itemStr);

      if (item.expires && Date.now() > item.expires) {
        localStorage.removeItem(key);
        return null;
      }

      return item.value;
    } catch {
      return null;
    }
  }

  static removeItem(key: string): void {
    localStorage.removeItem(key);
  }

  static clear(): void {
    localStorage.clear();
  }
}

// 日期格式化工具
export class DateHelper {
  static formatDate(date: Date | string, format: 'short' | 'long' | 'time' = 'short'): string {
    const d = typeof date === 'string' ? new Date(date) : date;

    const options: Intl.DateTimeFormatOptions = {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    };

    if (format === 'long') {
      options.hour = '2-digit';
      options.minute = '2-digit';
      options.second = '2-digit';
    }

    if (format === 'time') {
      delete options.year;
      delete options.month;
      delete options.day;
      options.hour = '2-digit';
      options.minute = '2-digit';
    }

    return d.toLocaleDateString('zh-CN', options);
  }

  static relativeTime(date: Date | string): string {
    const d = typeof date === 'string' ? new Date(date) : date;
    const now = new Date();
    const diff = now.getTime() - d.getTime();

    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 1) return '刚刚';
    if (minutes < 60) return `${minutes}分钟前`;
    if (hours < 24) return `${hours}小时前`;
    if (days < 7) return `${days}天前`;

    return this.formatDate(d, 'short');
  }
}

import type { CollectionSourceStatistics } from '@/api/crawler';

export type AttentionSeverity = 'critical' | 'high' | 'medium';
export type CrawlerAlertFilter = 'critical' | 'high' | 'stalled' | 'inactive';
export type AlertActionTarget = 'crawler' | 'play-sources';

export interface AttentionSourceItem {
  source: CollectionSourceStatistics;
  severity: AttentionSeverity;
  score: number;
