export const getHoursSince = (timestamp?: string | null) => {
  if (!timestamp) {
    return null;
  }

  const parsed = new Date(timestamp).getTime();
  if (Number.isNaN(parsed)) {
    return null;
  }

  return (Date.now() - parsed) / (1000 * 60 * 60);
};

export const buildAttentionSourceItem = (
  source: CollectionSourceStatistics,
): AttentionSourceItem | null => {
  const reasons: string[] = [];
  const highlights: string[] = [];
  let score = 0;

  if (source.dailyEnabled && source.totalCrawled === 0) {
    reasons.push('已启用日采集但暂无入库媒体');
    score += 5;
  }

  if (source.totalPlaySources > 0 && source.activePlaySources === 0) {
    reasons.push('存在播放源但当前无活跃源');
    highlights.push('0 活跃源');
    score += 6;
  }

  if (source.qualityScore < 55) {
    reasons.push(`质量分偏低（${source.qualityScore}）`);
    highlights.push(`质量 ${source.qualityScore}`);
    score += 5;
  } else if (source.qualityScore < 70) {
    reasons.push(`质量分待提升（${source.qualityScore}）`);
    highlights.push(`质量 ${source.qualityScore}`);
    score += 3;
  } else if (source.qualityScore < 75) {
    reasons.push(`质量分待提升（${source.qualityScore}）`);
    score += 2;
  }

  if (source.extractionCoverage < 40) {
    reasons.push(`提取覆盖偏低（${source.extractionCoverage}%）`);
    highlights.push(`提取 ${source.extractionCoverage}%`);
    score += 3;
  } else if (source.extractionCoverage < 60) {
    reasons.push(`提取覆盖待提升（${source.extractionCoverage}%）`);
    highlights.push(`提取 ${source.extractionCoverage}%`);
    score += 2;
  }

  if (source.activeRate < 35) {
    reasons.push(`可用率偏低（${source.activeRate}%）`);
    highlights.push(`可用率 ${source.activeRate}%`);
    score += 5;
  } else if (source.activeRate < 50) {
    reasons.push(`可用率偏低（${source.activeRate}%）`);
    highlights.push(`可用率 ${source.activeRate}%`);
    score += 3;
  } else if (source.activeRate < 70) {
    reasons.push(`可用率波动（${source.activeRate}%）`);
    score += 2;
  }

  const hoursSinceLastChecked = getHoursSince(source.lastCheckedAt);
  if (source.totalPlaySources > 0 && hoursSinceLastChecked === null) {
    reasons.push('尚未完成播放源稳定性校验');
    highlights.push('未校验');
    score += 4;
  } else if (hoursSinceLastChecked !== null && hoursSinceLastChecked >= 168) {
    reasons.push(`距上次校验已超过 ${Math.floor(hoursSinceLastChecked)} 小时`);
    highlights.push(`${Math.floor(hoursSinceLastChecked)}h 未校验`);
    score += 4;
  } else if (hoursSinceLastChecked !== null && hoursSinceLastChecked >= 72) {
    reasons.push(`距上次校验已超过 ${Math.floor(hoursSinceLastChecked)} 小时`);
    highlights.push(`${Math.floor(hoursSinceLastChecked)}h 未校验`);
    score += 2;
  }

  const hoursSinceLastCrawled = getHoursSince(source.lastCrawled);
  if (source.dailyEnabled && hoursSinceLastCrawled !== null && hoursSinceLastCrawled >= 168) {
    reasons.push(`最近入库已停滞约 ${Math.floor(hoursSinceLastCrawled)} 小时`);
    highlights.push('入库停滞');
    score += 3;
  }

  if (source.dailyEnabled && !source.lastCrawled) {
    reasons.push('近期没有采集入库记录');
    highlights.push('无入库');
    score += 3;
  }

  if (source.dailyEnabled && source.recentMedia7d === 0 && source.totalCrawled > 0) {
    reasons.push('最近 7 天没有新增媒体');
    highlights.push('7d 0 新增');
    score += 2;
  }

  if (source.activeMedia === 0 && source.totalCrawled > 0) {
    reasons.push('已有入库媒体但当前没有活跃媒体');
    score += 2;
  }

  if (reasons.length === 0) {
    return null;
  }

  const needsCrawlerInvestigation =
    (source.dailyEnabled && source.totalCrawled === 0) ||
    (source.dailyEnabled && (!source.lastCrawled || (hoursSinceLastCrawled ?? 0) >= 168)) ||
    source.qualityScore < 70 ||
    (source.activeMedia === 0 && source.totalCrawled > 0);

  const needsPlaySourceInvestigation =
    (source.totalPlaySources > 0 && source.activePlaySources === 0) ||
    source.activeRate < 50 ||
    (source.totalPlaySources > 0 && (hoursSinceLastChecked === null || hoursSinceLastChecked >= 72));

  const recommendedAction =
    needsPlaySourceInvestigation &&
    (!needsCrawlerInvestigation ||
      source.activePlaySources === 0 ||
      source.activeRate < 35 ||
      (hoursSinceLastChecked ?? 0) >= 168)
      ? {
          target: 'play-sources' as const,
          label: '优先排查播放源',
          description: '先检查失效链接、校验时效和活跃源恢复情况。',
        }
      : {
          target: 'crawler' as const,
          label: '优先检查来源策略',
          description: '先核查采集链路、入库停滞和来源抓取质量。',
        };

  return {
    source,
    reasons: reasons.slice(0, 3),
    highlights: highlights.slice(0, 3),
    score,
    severity: score >= 10 ? 'critical' : score >= 6 ? 'high' : 'medium',
    recommendedAction,
  };
};

export const compareAttentionSources = (left: AttentionSourceItem, right: AttentionSourceItem) => {
  return (
    right.score - left.score ||
    (getHoursSince(right.source.lastCheckedAt) ?? -1) -
      (getHoursSince(left.source.lastCheckedAt) ?? -1) ||
    left.source.qualityScore - right.source.qualityScore ||
    left.source.activeRate - right.source.activeRate
  );
};

export const matchesCrawlerAlertFilter = (
  source: CollectionSourceStatistics,
  filter: CrawlerAlertFilter,
) => {
  const attentionItem = buildAttentionSourceItem(source);

  if (filter === 'critical') {
    return attentionItem?.severity === 'critical';
  }

  if (filter === 'high') {
    return attentionItem?.severity === 'high';
  }

  if (filter === 'inactive') {
    return source.totalPlaySources > 0 && source.activePlaySources === 0;
  }

  const hoursSinceLastCrawled = getHoursSince(source.lastCrawled);
  return source.dailyEnabled && (hoursSinceLastCrawled === null || hoursSinceLastCrawled >= 168);
};

export const getErrorMessage = (error: unknown, fallback: string) => {
  if (error && typeof error === 'object') {
    const response = (error as { response?: { data?: { message?: string | string[] } } }).response;
    const message = response?.data?.message;

    if (Array.isArray(message)) {
      return message.join('；');
    }

    if (typeof message === 'string' && message.trim()) {
      return message;
    }
  }

  return error instanceof Error ? error.message : fallback;
};

import { ElMessage, ElNotification } from 'element-plus';
// import type { AxiosError } from 'axios'; // 暂时注释，以后可能用到

// 定义错误类型
export interface ApiError {
  message: string;
  status: number;
  data?: any;
}

export interface BusinessError {
  code: string;
  message: string;
  data?: any;
}

// 全局错误处理器
export class GlobalErrorHandler {
  // 通用错误处理方法
  static handle(error: any, defaultMessage: string = '操作失败'): ApiError {
    return this.handleApiError(error, defaultMessage);
  }

  // 处理API错误
  static handleApiError(error: any, defaultMessage: string = '操作失败'): ApiError {
    console.error('API Error:', error);

    // 提取错误信息
    let message = defaultMessage;
    let statusCode = 500;

    if (error.response) {
      // 服务器响应错误
      statusCode = error.response.status;
      const data = error.response.data;

      if (data && data.message) {
        message = data.message;
      } else if (data && data.error) {
        message = data.error;
      } else {
        switch (statusCode) {
          case 400:
            message = '请求参数错误';
            break;
          case 401:
            message = '未授权访问，请重新登录';
            break;
          case 403:
            message = '权限不足';
            break;
          case 404:
            message = '请求的资源不存在';
            break;
          case 409:
            message = '资源冲突';
            break;
          case 422:
            message = '数据验证失败';
            break;
          case 500:
            message = '服务器内部错误';
            break;
          case 502:
            message = '网关错误';
            break;
          case 503:
            message = '服务暂时不可用';
            break;
          case 504:
            message = '网关超时';
            break;
          default:
            message = `HTTP ${statusCode} 错误`;
        }
      }
    } else if (error.request) {
      // 网络错误
      message = '网络连接失败，请检查网络设置';
    } else {
      // 其他错误
      message = error.message || defaultMessage;
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    // 特殊错误处理
    if (statusCode === 401) {
      // 未授权错误，可能需要重新登录
      this.handleUnauthorizedError();
    }

    return {
      message,
      status: statusCode,
      data: error.response?.data,
    };
  }

  // 处理未授权错误
  static handleUnauthorizedError() {
    // 清除本地存储的认证信息
    localStorage.removeItem('token');

    // 显示通知
    ElNotification({
      title: '会话过期',
      message: '您的登录会话已过期，请重新登录',
      type: 'warning',
      duration: 0, // 持续显示直到用户操作
    });

    // 3秒后跳转到登录页面
    setTimeout(() => {
      window.location.href = '/login';
    }, 3000);
  }

  // 处理表单验证错误
  static handleValidationError(errors: Record<string, string[]>) {
    console.error('Validation Errors:', errors);

    // 构建错误消息
    const errorMessages = Object.entries(errors)
      .map(([field, messages]) => `${field}: ${messages.join(', ')}`)
      .join('\n');

    // 显示错误提示
    ElMessage({
      message: `表单验证失败:\n${errorMessages}`,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return errorMessages;
  }

  // 处理业务逻辑错误
  static handleBusinessError(error: BusinessError) {
    console.error('Business Error:', error);

    // 根据错误代码显示特定消息
    const errorMap: Record<string, string> = {
      MEDIA_NOT_FOUND: '影视资源不存在',
      PLAY_SOURCE_NOT_FOUND: '播放源不存在',
      USER_ALREADY_EXISTS: '用户已存在',
      INVALID_CREDENTIALS: '用户名或密码错误',
      TOKEN_EXPIRED: '令牌已过期',
      INSUFFICIENT_PERMISSIONS: '权限不足',
      RESOURCE_CONFLICT: '资源冲突',
      VALIDATION_FAILED: '数据验证失败',
      NETWORK_ERROR: '网络连接失败',
      SERVER_ERROR: '服务器错误',
      RATE_LIMIT_EXCEEDED: '请求过于频繁，请稍后再试',
      INVALID_INPUT: '输入数据无效',
      OPERATION_NOT_ALLOWED: '不允许此操作',
      RESOURCE_LOCKED: '资源已被锁定',
      QUOTA_EXCEEDED: '配额已满',
      SERVICE_UNAVAILABLE: '服务暂时不可用',
    };

    const message = errorMap[error.code] || error.message || '操作失败';

    // 显示错误提示
    ElMessage({
      message,
      type: 'warning',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理网络错误
  static handleNetworkError(error: any) {
    console.error('Network Error:', error);

    let message = '网络连接失败';

    if (error.code) {
      switch (error.code) {
        case 'ECONNABORTED':
          message = '请求超时';
          break;
        case 'ENOTFOUND':
          message = '域名解析失败';
          break;
        case 'ECONNREFUSED':
          message = '连接被拒绝';
          break;
        case 'ETIMEDOUT':
          message = '连接超时';
          break;
        case 'EHOSTUNREACH':
          message = '主机不可达';
          break;
        case 'ENETUNREACH':
          message = '网络不可达';
          break;
        default:
          message = `网络错误: ${error.code}`;
      }
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理播放错误
  static handlePlaybackError(error: any) {
    console.error('Playback Error:', error);

    let message = '视频播放失败';

    if (error.name) {
      switch (error.name) {
        case 'NotAllowedError':
          message = '播放被阻止，请点击播放按钮';
          break;
        case 'NotSupportedError':
          message = '不支持的视频格式';
          break;
        case 'AbortError':
          message = '播放被中止';
          break;
        case 'NetworkError':
          message = '网络连接问题导致播放失败';
          break;
        case 'DecodeError':
          message = '视频解码失败';
          break;
        case 'SourceUnavailableError':
          message = '视频源不可用';
          break;
        default:
          message = `播放错误: ${error.name}`;
      }
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理异步操作错误
  static async handleAsyncError<T>(
    promise: Promise<T>,
    options: {
      defaultMessage?: string;
      showError?: boolean;
      showNotification?: boolean;
    } = {},
  ): Promise<{ success: boolean; data?: T; error?: ApiError }> {
    const { defaultMessage = '操作失败', showError = true, showNotification = false } = options;

    try {
      const result = await promise;
      return { success: true, data: result };
    } catch (error) {
      const errorInfo = this.handleApiError(error, defaultMessage);

      if (showNotification) {
        ElNotification({
          title: '操作失败',
          message: errorInfo.message,
          type: 'error',
        });
      }

      return { success: false, error: errorInfo };
    }
  }
}

// 移动端优化功能
export const mobileOptimizations = {
  // 设备检测
  deviceInfo: {
    isMobile: /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
      navigator.userAgent,
    ),
    isIOS: /iPad|iPhone|iPod/.test(navigator.userAgent),
    isAndroid: /Android/.test(navigator.userAgent),
    isTablet: /iPad|Android/.test(navigator.userAgent) && window.innerWidth > 768,
    isLandscape: window.innerWidth > window.innerHeight,
    hasTouch: 'ontouchstart' in window || navigator.maxTouchPoints > 0,
    supportsVibration: 'vibrate' in navigator,
    supportsDeviceOrientation: 'DeviceOrientationEvent' in window,
    supportsDeviceMotion: 'DeviceMotionEvent' in window,
  },

  // 屏幕信息
  screenInfo: {
    width: window.innerWidth,
    height: window.innerHeight,
    pixelRatio: window.devicePixelRatio || 1,
    orientation: window.innerWidth > window.innerHeight ? 'landscape' : 'portrait',
    safeArea: { top: 0, right: 0, bottom: 0, left: 0 },
  },

  // 获取安全区域
  getSafeAreaInsets() {
    const style = getComputedStyle(document.documentElement);
    return {
      top: parseInt(style.getPropertyValue('--safe-area-inset-top') || '0'),
      right: parseInt(style.getPropertyValue('--safe-area-inset-right') || '0'),
      bottom: parseInt(style.getPropertyValue('--safe-area-inset-bottom') || '0'),
      left: parseInt(style.getPropertyValue('--safe-area-inset-left') || '0'),
    };
  },

  // 手势识别器
  gestureRecognizer: {
    startPoint: { x: 0, y: 0 },
    lastPoint: { x: 0, y: 0 },
    startTime: 0,
    tapCount: 0,
    lastTapTime: 0,
    isLongPress: false,
    isSwipe: false,
    isPinch: false,
    pinchDistance: 0,
    longPressTimer: null as number | null,

    // 重置状态
    reset() {
      this.startPoint = { x: 0, y: 0 };
      this.lastPoint = { x: 0, y: 0 };
      this.startTime = 0;
      this.isLongPress = false;
      this.isSwipe = false;
      this.isPinch = false;
      this.pinchDistance = 0;

      if (this.longPressTimer) {
        clearTimeout(this.longPressTimer);
        this.longPressTimer = null;
      }
    },

    // 识别轻触
    recognizeTap(touch: Touch) {
      const now = Date.now();
      const timeSinceLastTap = now - this.lastTapTime;

      if (timeSinceLastTap < 300 && timeSinceLastTap > 50) {
        this.tapCount++;
        if (this.tapCount === 2) {
          return { type: 'doubleTap', touch };
        }
      } else {
        this.tapCount = 1;
      }

      this.lastTapTime = now;
      return { type: 'tap', touch };
    },

    // 识别长按
    recognizeLongPress(touch: Touch): Promise<{ type: 'longPress'; touch: Touch }> {
      return new Promise(resolve => {
        this.longPressTimer = window.setTimeout(() => {
          this.isLongPress = true;
          resolve({ type: 'longPress', touch });
        }, 500);
      });
    },

    // 识别滑动
    recognizeSwipe(startTouch: Touch, endTouch: Touch) {
      const deltaX = endTouch.clientX - startTouch.clientX;
      const deltaY = endTouch.clientY - startTouch.clientY;
      const distance = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
      const deltaTime = Date.now() - this.startTime;

      // 最小距离和最大时间限制
      if (distance > 30 && deltaTime < 500) {
        let direction: 'up' | 'down' | 'left' | 'right';

        if (Math.abs(deltaX) > Math.abs(deltaY)) {
          direction = deltaX > 0 ? 'right' : 'left';
        } else {
          direction = deltaY > 0 ? 'down' : 'up';
        }

        return {
          type: 'swipe',
          direction,
          distance,
          velocity: distance / deltaTime,
          startTouch,
          endTouch,
        };
      }

      return null;
    },

    // 识别缩放
    recognizePinch(touches: Touch[]) {
      if (touches.length < 2) return null;

      const dx = touches[0].clientX - touches[1].clientX;
      const dy = touches[0].clientY - touches[1].clientY;
      const distance = Math.sqrt(dx * dx + dy * dy);

      if (this.pinchDistance > 0) {
        const scale = distance / this.pinchDistance;
        return {
          type: 'pinch',
          scale,
          center: {
            x: (touches[0].clientX + touches[1].clientX) / 2,
            y: (touches[0].clientY + touches[1].clientY) / 2,
          },
        };
      }

      this.pinchDistance = distance;
      return null;
    },
  },

  // 触摸事件处理
  addTouchHandlers(
    element: HTMLElement,
    handlers: {
      onTouchStart?: (e: TouchEvent) => void;
      onTouchMove?: (e: TouchEvent) => void;
      onTouchEnd?: (e: TouchEvent) => void;
      onGesture?: (gesture: any) => void;
    },
  ) {
    let gestureTimer: number | null = null;

    const handleStart = (e: TouchEvent) => {
      const touch = e.touches[0];
      this.gestureRecognizer.reset();
      this.gestureRecognizer.startPoint = { x: touch.clientX, y: touch.clientY };
      this.gestureRecognizer.lastPoint = { x: touch.clientX, y: touch.clientY };
      this.gestureRecognizer.startTime = Date.now();

      // 启动长按检测
      if (e.touches.length === 1 && handlers.onGesture) {
        this.gestureRecognizer
          .recognizeLongPress(touch)
          .then(gesture => handlers.onGesture!(gesture))
          .catch(() => {}); // 忽略取消的长按
      }

      if (handlers.onTouchStart) {
        handlers.onTouchStart(e);
      }
    };

    const handleMove = (e: TouchEvent) => {
      if (e.touches.length > 0) {
        const touch = e.touches[0];
        this.gestureRecognizer.lastPoint = { x: touch.clientX, y: touch.clientY };

        // 取消长按
        if (this.gestureRecognizer.longPressTimer) {
          clearTimeout(this.gestureRecognizer.longPressTimer);
          this.gestureRecognizer.longPressTimer = null;
        }

        // 检测缩放
        if (e.touches.length === 2 && handlers.onGesture) {
          const pinchGesture = this.gestureRecognizer.recognizePinch(Array.from(e.touches));
          if (pinchGesture) {
            handlers.onGesture(pinchGesture);
          }
        }
      }

      if (handlers.onTouchMove) {
        handlers.onTouchMove(e);
      }
    };

    const handleEnd = (e: TouchEvent) => {
      if (this.gestureRecognizer.longPressTimer) {
        clearTimeout(this.gestureRecognizer.longPressTimer);
        this.gestureRecognizer.longPressTimer = null;
      }

      if (e.changedTouches.length > 0 && handlers.onGesture) {
        const touch = e.changedTouches[0];
        const duration = Date.now() - this.gestureRecognizer.startTime;

        // 检测轻触
        if (
          duration < 200 &&
          !this.gestureRecognizer.isSwipe &&
          !this.gestureRecognizer.isLongPress
        ) {
          const tapGesture = this.gestureRecognizer.recognizeTap(touch);
          if (tapGesture) {
            handlers.onGesture(tapGesture);
          }
        }

        // 检测滑动
        if (!this.gestureRecognizer.isLongPress) {
          const swipeGesture = this.gestureRecognizer.recognizeSwipe(
            this.gestureRecognizer.startPoint as Touch,
            touch,
          );
          if (swipeGesture) {
            handlers.onGesture(swipeGesture);
          }
        }
      }

      if (handlers.onTouchEnd) {
        handlers.onTouchEnd(e);
      }

      // 延迟重置手势状态
      if (gestureTimer) {
        clearTimeout(gestureTimer);
      }
      gestureTimer = window.setTimeout(() => {
        this.gestureRecognizer.reset();
      }, 300);
    };

    element.addEventListener('touchstart', handleStart, { passive: false });
    element.addEventListener('touchmove', handleMove, { passive: false });
    element.addEventListener('touchend', handleEnd, { passive: false });

    // 返回清理函数
    return () => {
      element.removeEventListener('touchstart', handleStart);
      element.removeEventListener('touchmove', handleMove);
      element.removeEventListener('touchend', handleEnd);
      if (gestureTimer) {
        clearTimeout(gestureTimer);
      }
    };
  },

  // 移除触摸事件处理
  removeTouchHandlers(
    element: HTMLElement,
    handlers: {
      onTouchStart?: (e: TouchEvent) => void;
      onTouchMove?: (e: TouchEvent) => void;
      onTouchEnd?: (e: TouchEvent) => void;
    },
  ) {
    if (handlers.onTouchStart) {
      element.removeEventListener('touchstart', handlers.onTouchStart);
    }
    if (handlers.onTouchMove) {
      element.removeEventListener('touchmove', handlers.onTouchMove);
    }
    if (handlers.onTouchEnd) {
      element.removeEventListener('touchend', handlers.onTouchEnd);
    }
  },

  // 检测是否为移动设备
  isMobileDevice(): boolean {
    return this.deviceInfo.isMobile;
  },

  // 优化触摸目标大小
  optimizeTouchTargets() {
    const targets = document.querySelectorAll(
      '.video-player__control-button, .clickable, [role="button"]',
    );
    targets.forEach(target => {
      const element = target as HTMLElement;
      const rect = element.getBoundingClientRect();

      // 确保最小触摸目标44x44px
      if (rect.width < 44 || rect.height < 44) {
        const newWidth = Math.max(44, rect.width);
        const newHeight = Math.max(44, rect.height);

        element.style.minWidth = `${newWidth}px`;
        element.style.minHeight = `${newHeight}px`;
        element.style.display = 'flex';
        element.style.alignItems = 'center';
        element.style.justifyContent = 'center';
      }
    });
  },

  // 适配安全区域
  adaptSafeArea() {
    const safeArea = this.screenInfo.safeArea;

    // 添加CSS变量
    document.documentElement.style.setProperty('--safe-area-inset-top', `${safeArea.top}px`);
    document.documentElement.style.setProperty('--safe-area-inset-right', `${safeArea.right}px`);
    document.documentElement.style.setProperty('--safe-area-inset-bottom', `${safeArea.bottom}px`);
    document.documentElement.style.setProperty('--safe-area-inset-left', `${safeArea.left}px`);

    // 自动调整元素边距
    const elements = document.querySelectorAll('.safe-area-top, .safe-area-bottom');
    elements.forEach(element => {
      const el = element as HTMLElement;
      if (el.classList.contains('safe-area-top')) {
        el.style.paddingTop = `${safeArea.top}px`;
      }
      if (el.classList.contains('safe-area-bottom')) {
        el.style.paddingBottom = `${safeArea.bottom}px`;
      }
    });
  },

  // 防抖动
  debounce<T extends (...args: any[]) => any>(func: T, wait: number): T {
    let timeout: number | null = null;

    return ((...args: Parameters<T>) => {
      if (timeout) {
        clearTimeout(timeout);
      }

      timeout = window.setTimeout(() => {
        func(...args);
        timeout = null;
      }, wait) as unknown as number;
    }) as T;
  },

  // 节流
  throttle<T extends (...args: any[]) => any>(func: T, limit: number): T {
    let inThrottle: boolean = false;

    return ((...args: Parameters<T>) => {
      if (!inThrottle) {
        func(...args);
        inThrottle = true;
        setTimeout(() => {
          inThrottle = false;
        }, limit);
      }
    }) as T;
  },

  // 检测设备性能
  detectPerformance() {
    const connection =
      (navigator as any).connection ||
      (navigator as any).mozConnection ||
      (navigator as any).webkitConnection;

    return {
      deviceMemory: (navigator as any).deviceMemory || 4,
      hardwareConcurrency: navigator.hardwareConcurrency || 4,
      connection: connection
        ? {
            effectiveType: connection.effectiveType,
            downlink: connection.downlink,
            rtt: connection.rtt,
          }
        : null,
      pixelRatio: window.devicePixelRatio || 1,
    };
  },

  // 自适应优化
  applyAdaptiveOptimizations() {
    const performance = this.detectPerformance();
    const isLowEnd = performance.deviceMemory < 4 || performance.hardwareConcurrency < 4;

    if (isLowEnd) {
      // 低端设备优化
      document.body.classList.add('low-performance');

      // 减少动画
      const style = document.createElement('style');
      style.textContent = `
        .low-performance *,
        .low-performance *::before,
        .low-performance *::after {
          animation-duration: 0.01ms !important;
          animation-iteration-count: 1 !important;
          transition-duration: 0.01ms !important;
        }
      `;
      document.head.appendChild(style);
    }

    if (performance.connection) {
      const isSlowConnection =
        performance.connection.effectiveType === 'slow-2g' ||
        performance.connection.effectiveType === '2g' ||
        performance.connection.downlink < 0.5;

      if (isSlowConnection) {
        document.body.classList.add('slow-connection');
      }
    }
  },
};

import { ref, onMounted, onUnmounted } from 'vue';

const DEV = import.meta.env.DEV;

// 性能监控工具
export class PerformanceMonitor {
  private static metrics = {
    pageLoad: 0,
    apiCalls: 0,
    apiTotalTime: 0,
    renderTime: 0,
    memoryUsage: [] as number[],
    errors: 0,
    warnings: 0,
  };

  private static observers = new Set<PerformanceObserver>();

  // 监控页面加载性能
  static trackPageLoad() {
    if (typeof window === 'undefined' || !window.performance) return;

    const navigation = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
    if (navigation) {
      this.metrics.pageLoad = navigation.loadEventEnd - navigation.loadEventStart;

      if (DEV) {
        console.log(`[Performance] page load: ${this.metrics.pageLoad}ms`);
      }

      // 如果加载时间过长，发出警告
      if (this.metrics.pageLoad > 3000) {
        if (DEV) {
          console.warn('页面加载时间过长，建议优化');
        }
        this.metrics.warnings++;
      }
    }
  }

  // 监控API调用性能
  static trackApiCall(duration: number, endpoint: string) {
    this.metrics.apiCalls++;
    this.metrics.apiTotalTime += duration;

    const avgTime = this.metrics.apiTotalTime / this.metrics.apiCalls;

    if (DEV) {
      console.log(`[Performance] API ${endpoint}: ${duration}ms (avg ${avgTime.toFixed(2)}ms)`);
    }

    // 如果API调用时间过长，发出警告
    if (duration > 5000) {
      if (DEV) {
        console.warn(`API调用时间过长: ${endpoint} - ${duration}ms`);
      }
      this.metrics.warnings++;
    }
  }

  // 监控组件渲染性能
  static trackComponentRender(componentName: string, duration: number) {
    this.metrics.renderTime = duration;

    if (DEV) {
      console.log(`[Performance] component ${componentName}: ${duration}ms`);
    }

    // 如果渲染时间过长，发出警告
    if (duration > 100) {
      if (DEV) {
        console.warn(`组件渲染时间过长: ${componentName} - ${duration}ms`);
      }
      this.metrics.warnings++;
    }
  }

  // 监控内存使用
  static trackMemoryUsage() {
    if (typeof window === 'undefined' || !window.performance) return;

    const memory = (performance as any).memory;
    if (memory) {
      const usedMB = memory.usedJSHeapSize / 1024 / 1024;
      const totalMB = memory.totalJSHeapSize / 1024 / 1024;
      const limitMB = memory.jsHeapSizeLimit / 1024 / 1024;

      this.metrics.memoryUsage.push(usedMB);

      // 只保留最近100条记录
      if (this.metrics.memoryUsage.length > 100) {
        this.metrics.memoryUsage = this.metrics.memoryUsage.slice(-100);
      }

      if (DEV) {
        console.log(
          `[Performance] memory: ${usedMB.toFixed(2)}MB / ${totalMB.toFixed(2)}MB (limit ${limitMB.toFixed(2)}MB)`,
        );
      }

      // 如果内存使用过高，发出警告
      if (usedMB > totalMB * 0.9) {
        if (DEV) {
          console.warn('内存使用过高，建议检查内存泄漏');
        }
        this.metrics.warnings++;
      }
    }
  }

  // 监控错误
  static trackError(error: Error, context?: string) {
    this.metrics.errors++;
    console.error(`❌ 错误 [${context || '未知'}]:`, error);
  }

  // 获取性能报告
  static getReport() {
    const avgApiTime =
      this.metrics.apiCalls > 0 ? this.metrics.apiTotalTime / this.metrics.apiCalls : 0;

    const avgMemory =
      this.metrics.memoryUsage.length > 0
        ? this.metrics.memoryUsage.reduce((sum, mem) => sum + mem, 0) /
          this.metrics.memoryUsage.length
        : 0;

    return {
      timestamp: new Date().toISOString(),
      summary: {
        pageLoadTime: `${this.metrics.pageLoad}ms`,
        apiCalls: this.metrics.apiCalls,
        avgApiTime: `${avgApiTime.toFixed(2)}ms`,
        renderTime: `${this.metrics.renderTime}ms`,
        avgMemory: `${avgMemory.toFixed(2)}MB`,
        errors: this.metrics.errors,
        warnings: this.metrics.warnings,
      },
      recommendations: this.generateRecommendations(),
    };
  }

  // 生成性能优化建议
  private static generateRecommendations(): string[] {
    const recommendations: string[] = [];

    if (this.metrics.pageLoad > 3000) {
      recommendations.push(
        '页面加载时间过长，建议：\n  - 优化图片加载，使用懒加载\n  - 减少首屏内容\n  - 启用Gzip压缩\n  - 使用CDN加速',
      );
    }

    if (this.metrics.apiCalls > 0) {
      const avgApiTime = this.metrics.apiTotalTime / this.metrics.apiCalls;
      if (avgApiTime > 2000) {
        recommendations.push(
          'API调用平均时间过长，建议：\n  - 启用API缓存\n  - 优化数据库查询\n  - 使用分页加载\n  - 实现请求去重',
        );
      }
    }

    if (this.metrics.renderTime > 100) {
      recommendations.push(
        '组件渲染时间过长，建议：\n  - 使用虚拟滚动\n  - 优化组件结构\n  - 减少响应式数据\n  - 使用shouldUpdate优化',
      );
    }

    const avgMemory =
      this.metrics.memoryUsage.length > 0
        ? this.metrics.memoryUsage.reduce((sum, mem) => sum + mem, 0) /
          this.metrics.memoryUsage.length
        : 0;

    if (avgMemory > 50) {
      recommendations.push(
        '内存使用过高，建议：\n  - 检查内存泄漏\n  - 及时清理无用数据\n  - 优化大数据结构\n  - 使用WeakMap/WeakSet',
      );
    }

    if (this.metrics.errors > 5) {
      recommendations.push(
        '错误数量较多，建议：\n  - 增强错误处理\n  - 添加错误边界\n  - 完善日志记录\n  - 实现错误恢复机制',
      );
    }

    return recommendations;
  }

  // 重置指标
  static reset() {
    this.metrics = {
      pageLoad: 0,
      apiCalls: 0,
      apiTotalTime: 0,
      renderTime: 0,
      memoryUsage: [],
      errors: 0,
      warnings: 0,
    };
  }
}

// 高阶性能监控Hook
export function usePerformance(componentName: string) {
  const renderStartTime = ref(0);
  const renderEndTime = ref(0);
  const mountStartTime = ref(0);
  const mountEndTime = ref(0);

  onMounted(() => {
    mountStartTime.value = performance.now();

    // 监控组件挂载性能
    requestAnimationFrame(() => {
      mountEndTime.value = performance.now();
      const mountDuration = mountEndTime.value - mountStartTime.value;
      PerformanceMonitor.trackComponentRender(`${componentName}-mount`, mountDuration);
    });
  });

  onUnmounted(() => {
    // 组件卸载时的清理工作
  });

  const trackRenderStart = () => {
    renderStartTime.value = performance.now();
  };

  const trackRenderEnd = () => {
    renderEndTime.value = performance.now();
    const renderDuration = renderEndTime.value - renderStartTime.value;
    PerformanceMonitor.trackComponentRender(`${componentName}-render`, renderDuration);
  };

  return {
    trackRenderStart,
    trackRenderEnd,
    getRenderTime: () => renderEndTime.value - renderStartTime.value,
    getMountTime: () => mountEndTime.value - mountStartTime.value,
  };
}

// API调用性能监控Hook
export function useApiPerformance() {
  const trackApiCall = async <T>(promise: Promise<T>, endpoint: string): Promise<T> => {
    const startTime = performance.now();

    try {
      const result = await promise;
      const endTime = performance.now();
      const duration = endTime - startTime;
      PerformanceMonitor.trackApiCall(duration, endpoint);
      return result;
    } catch (error) {
      const endTime = performance.now();
      const duration = endTime - startTime;
      PerformanceMonitor.trackApiCall(duration, endpoint);
      PerformanceMonitor.trackError(error as Error, `API:${endpoint}`);
      throw error;
    }
  };

  return { trackApiCall };
}

// 内存监控Hook
export function useMemoryMonitor(interval = 5000) {
  let timer: number | null = null;

  onMounted(() => {
    timer = setInterval(() => {
      PerformanceMonitor.trackMemoryUsage();
    }, interval);
  });

  onUnmounted(() => {
    if (timer) {
      clearInterval(timer);
    }
  });

  const getMemoryReport = () => {
    return PerformanceMonitor.getReport();
  };

  return { getMemoryReport };
}

// 页面性能监控Hook
export function usePagePerformance() {
  onMounted(() => {
    // 等待页面完全加载
    if (document.readyState === 'complete') {
      PerformanceMonitor.trackPageLoad();
    } else {
      window.addEventListener('load', () => {
        PerformanceMonitor.trackPageLoad();
      });
    }
  });

  const getPerformanceReport = () => {
    return PerformanceMonitor.getReport();
  };

  return { getPerformanceReport };
}

import type { Router } from 'vue-router';

export interface RouteMeta {
  title?: string;
  requiresAuth?: boolean;
  requiresAdmin?: boolean;
  preload?: boolean;
  keepAlive?: boolean;
  hideAuth?: boolean;
}

export class PreloadService {
  private router: Router;
  private preloadQueue: Set<string> = new Set();
  private preloadedRoutes: Set<string> = new Set();
  private observer: IntersectionObserver | null = null;
  private preloadTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(router: Router) {
    this.router = router;
    this.initPreloadObserver();
  }

  /**
   * 初始化预加载观察器
   */
  private initPreloadObserver() {
    if (typeof IntersectionObserver === 'undefined') {
      return;
    }

    this.observer = new IntersectionObserver(
      entries => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const preloadLink = entry.target as HTMLElement;
            const routeName = preloadLink.dataset.route;
            if (routeName) {
              this.preloadRoute(routeName);
            }
          }
        });
      },
      {
        rootMargin: '50px',
        threshold: 0.1,
      },
    );
  }

  /**
   * 添加预加载链接到观察器
   */
  observePreloadLink(element: HTMLElement, routeName: string) {
    if (this.observer) {
      element.dataset.route = routeName;
      this.observer.observe(element);
    }
  }

  /**
   * 预加载指定路由
   */
  async preloadRoute(routeName: string): Promise<void> {
    // 如果已经预加载或正在预加载，则跳过
    if (this.preloadedRoutes.has(routeName) || this.preloadQueue.has(routeName)) {
      return;
    }

    const route = this.router.resolve({ name: routeName });
    if (!route.matched.length) {
      return;
    }

    // 检查路由是否支持预加载
    const meta = route.matched[0].meta as RouteMeta;
    if (!meta?.preload) {
      return;
    }

    this.preloadQueue.add(routeName);

    try {
      // 模拟用户空闲时预加载
      if ('requestIdleCallback' in window) {
        await new Promise<void>(resolve => {
          window.requestIdleCallback(async () => {
            await this.doPreload(route);
            resolve();
          });
        });
      } else {
        // 回退方案：延迟预加载
        setTimeout(() => this.doPreload(route), 100);
      }
    } catch (error) {
      console.warn(`预加载路由 ${routeName} 失败:`, error);
      this.preloadQueue.delete(routeName);
    }
  }

  /**
   * 执行预加载
   */
  private async doPreload(route: { matched: any[] }): Promise<void> {
    try {
      // 触发动态导入
      const components = route.matched.map(matched => {
        return matched.components?.default || matched.components;
      });

      // 等待所有组件加载完成
      await Promise.all(
        components.filter(Boolean).map(component => {
          if (typeof component === 'function') {
            return component();
          }
          return Promise.resolve(component);
        }),
      );
    } catch (error) {
      console.warn('路由预加载失败:', error);
    }
  }

  /**
   * 预加载所有标记为预加载的路由
   */
  preloadAllRoutes(): void {
    this.router.getRoutes().forEach(route => {
      const meta = route.meta as RouteMeta;
      const routeName = route.name ? String(route.name) : '';
      if (meta?.preload && routeName && !this.preloadedRoutes.has(routeName)) {
        this.preloadRoute(routeName).catch(() => {
          // 静默失败，不影响用户体验
        });
      }
    });
  }

  /**
   * 根据用户行为智能预加载
   */
  initSmartPreload(): void {
    // 仅预加载核心路由（首页、详情页、观看页）
    const coreRoutes = ['home', 'media-detail', 'watch', 'recommendations'];

    // 页面加载完成后预加载核心路由
    window.addEventListener('load', () => {
      setTimeout(() => {
        coreRoutes.forEach(routeName => {
          if (this.shouldPreload(routeName)) {
            this.preloadRoute(routeName).catch(() => {
              // 静默失败
            });
          }
        });
      }, 2000); // 延迟时间增加：1秒 → 2秒
    });

    // 鼠标空闲时预加载（降低频率）
    document.addEventListener('mousemove', () => {
      if (this.preloadTimer) {
        clearTimeout(this.preloadTimer);
      }
      this.preloadTimer = setTimeout(() => {
        coreRoutes.forEach(routeName => {
          if (this.shouldPreload(routeName)) {
            this.preloadRoute(routeName).catch(() => {
              // 静默失败
            });
          }
        });
      }, 5000); // 增加延迟：2秒 → 5秒
    });

    // 高速网络下的智能预加载
    if ('connection' in navigator) {
      const connection = (navigator as any).connection;
      if (connection.effectiveType === '4g' && !connection.saveData) {
        // 仅在4G且未开启数据节省模式时预加载
        setTimeout(() => {
          coreRoutes.forEach(routeName => {
            if (this.shouldPreload(routeName)) {
              this.preloadRoute(routeName).catch(() => {
                // 静默失败
              });
            }
          });
        }, 3000);
      }
    }

    // 触摸设备上的保守预加载
    document.addEventListener(
      'touchstart',
      () => {
        // 仅预加载首页和推荐页
        ['home', 'recommendations'].forEach(routeName => {
          if (this.shouldPreload(routeName)) {
            this.preloadRoute(routeName).catch(() => {
              // 静默失败
            });
          }
        });
      },
      { once: true },
    );
  }

  /**
   * 判断是否应该预加载指定路由
   */
  private shouldPreload(routeName: string): boolean {
    const route = this.router.resolve({ name: routeName });
    if (!route.matched.length) {
      return false;
    }

    const meta = route.matched[0].meta as RouteMeta;
    if (!meta?.preload) {
      return false;
    }

    // 核心路由列表
    const coreRoutes = ['home', 'media-detail', 'watch', 'recommendations'];
    return coreRoutes.includes(routeName);
  }

  /**
   * 获取预加载状态
   */
  getPreloadStatus(): { preloaded: string[]; queued: string[] } {
    return {
      preloaded: Array.from(this.preloadedRoutes),
      queued: Array.from(this.preloadQueue),
    };
  }

  /**
   * 清理预加载观察器
   */
  destroy(): void {
    if (this.observer) {
      this.observer.disconnect();
      this.observer = null;
    }

    if (this.preloadTimer) {
      clearTimeout(this.preloadTimer);
      this.preloadTimer = null;
    }
  }
}

// 创建全局预加载服务实例
let preloadService: PreloadService | null = null;

/**
 * 初始化预加载服务
 */
export function initPreloadService(router: Router): PreloadService {
  if (!preloadService) {
    preloadService = new PreloadService(router);
    preloadService.initSmartPreload();
  }
  return preloadService;
}

/**
 * 获取预加载服务实例
 */
export function getPreloadService(): PreloadService | null {
  return preloadService;
}

/**
 * Vue指令：v-preload
 */
export const vPreload = {
  mounted(el: HTMLElement, binding: { value: string }) {
    const preloadService = getPreloadService();
    if (preloadService && binding.value) {
      preloadService.observePreloadLink(el, binding.value);
    }
  },
  unmounted(el: HTMLElement) {
    const preloadService = getPreloadService();
    if (preloadService) {
      (preloadService as any).observer?.unobserve(el);
    }
  },
};

const SEARCH_HISTORY_STORAGE_KEY = 'nest-tv.recent-searches';
const DEFAULT_HISTORY_LIMIT = 8;

export const normalizeSearchKeyword = (keyword: string) => keyword.trim().replace(/\s+/g, ' ');

export const dedupeKeywords = (keywords: string[], limit = DEFAULT_HISTORY_LIMIT) => {
  const seen = new Set<string>();

  return keywords
    .map(item => normalizeSearchKeyword(item))
    .filter(Boolean)
    .filter(item => {
      const cacheKey = item.toLocaleLowerCase();
      if (seen.has(cacheKey)) {
        return false;
      }

      seen.add(cacheKey);
      return true;
    })
    .slice(0, limit);
};

export const readRecentSearches = () => {
  try {
    const rawValue = globalThis.localStorage?.getItem(SEARCH_HISTORY_STORAGE_KEY);
    if (!rawValue) {
      return [];
    }

    const parsed = JSON.parse(rawValue);
    return Array.isArray(parsed) ? dedupeKeywords(parsed, DEFAULT_HISTORY_LIMIT) : [];
  } catch (error) {
    console.error('读取最近搜索失败:', error);
    return [];
  }
};

export const saveRecentSearch = (keyword: string) => {
  const nextKeyword = normalizeSearchKeyword(keyword);
  if (!nextKeyword) {
    return readRecentSearches();
  }

  const nextSearches = dedupeKeywords([nextKeyword, ...readRecentSearches()], DEFAULT_HISTORY_LIMIT);

  try {
    globalThis.localStorage?.setItem(SEARCH_HISTORY_STORAGE_KEY, JSON.stringify(nextSearches));
  } catch (error) {
    console.error('保存最近搜索失败:', error);
  }

  return nextSearches;
};

export const clearRecentSearches = () => {
  try {
    globalThis.localStorage?.removeItem(SEARCH_HISTORY_STORAGE_KEY);
  } catch (error) {
    console.error('清空最近搜索失败:', error);
  }

  return [] as string[];
};

export const filterRecentSearches = (keywords: string[], keyword: string, limit = 4) => {
  const normalizedKeyword = normalizeSearchKeyword(keyword).toLocaleLowerCase();
  if (!normalizedKeyword) {
    return dedupeKeywords(keywords, limit);
  }

  return dedupeKeywords(keywords.filter(item => item.toLocaleLowerCase().includes(normalizedKeyword)), limit);
};

