import { beforeEach, describe, expect, it, vi } from 'vitest';
import { flushPromises, mount, type VueWrapper } from '@vue/test-utils';
import LoginView from '@/views/LoginView.vue';
import SettingsView from '@/views/SettingsView.vue';
import AppLayout from '@/components/AppLayout.vue';

const {
  routeState,
  routerState,
  authStore,
  authApi,
  searchApi,
  setLocale,
} = vi.hoisted(() => {
  const session = {
    password: 'old-pass-123',
    profile: {
      id: 1,
      username: 'demo-user',
      email: 'demo@example.com',
      nickname: 'Demo',
      role: 'user',
      isActive: true,
      createdAt: '2025-01-01T00:00:00.000Z',
      updatedAt: '2025-01-01T00:00:00.000Z',
      recommendationSettings: {
        preferredTypes: ['movie'],
        preferredGenres: ['科幻'],
        excludedGenres: [],
        preferredKeywords: ['沙丘'],
        freshnessBias: 'balanced',
      },
    },
  };

  const authStore = {
    token: '',
    user: null as any,
    isLoading: false,
    get isAuthenticated() {
      return !!this.token;
    },
    login: vi.fn(async (credentials: { identifier: string; password: string }) => {
      authStore.isLoading = true;
      try {
        if (credentials.identifier !== 'demo-user' && credentials.identifier !== 'demo@example.com') {
          return { success: false, error: '用户名或密码错误' };
        }
        if (credentials.password !== session.password) {
          return { success: false, error: '用户名或密码错误' };
        }

        authStore.token = 'demo-token';
        authStore.user = { ...session.profile };
        return { success: true };
      } finally {
        authStore.isLoading = false;
      }
    }),
    logout: vi.fn(() => {
      authStore.token = '';
      authStore.user = null;
    }),
    fetchUserProfile: vi.fn(async () => {
      authStore.user = { ...session.profile };
    }),
  };

  return {
    routeState: {
      path: '/login',
      params: {} as Record<string, string>,
      query: {} as Record<string, string>,
    },
    routerState: {
      push: vi.fn(),
      replace: vi.fn(),
    },
    authStore,
    authApi: {
      getProfile: vi.fn(async () => ({ ...session.profile })),
      updateProfile: vi.fn(async (payload: any) => {
        session.profile = {
          ...session.profile,
          ...payload,
        };
        return { ...session.profile };
      }),
      changePassword: vi.fn(async ({ newPassword }: { newPassword: string }) => {
        session.password = newPassword;
        return { success: true };
      }),
    },
    searchApi: {
      getHistory: vi.fn(async () => ['沙丘']),
    },
    setLocale: vi.fn(),
  };
});

