    await saveButton!.trigger('click');
    await flushPromises();

    expect(authApi.updateProfile).toHaveBeenCalledWith(
      expect.objectContaining({
        recommendationSettings: expect.objectContaining({
          preferredKeywords: ['沙丘', '科幻'],
        }),
