      limit: 10,
      total: 1,
      totalPages: 1,
    });

    mount(WatchHistoryView, {
      global: {
        stubs: { RouterLink: RouterLinkStub },
      },
    });
    await flushPromises();

    expect(routerReplace).toHaveBeenCalledWith({
      name: 'watch-history',
      query: {
        isCompleted: 'true',
        sortBy: 'updatedAt',
        sortOrder: 'DESC',
      },
    });
